INSERT INTO `cms` (`id`, `title`, `ar_title`, `description`, `ar_description`, `type`, `status`, `flag`, `position`, `image`, `ar_image`, `created_on`, `updated_on`, `created_by`, `updated_by`) VALUES
(1, 'What is CFC Platform ?', 'What is CFC Platform ?', 'CFC is a digital lending platform that connects established businesses with investor (lenders). The platform uses technology to connect both parties through the principle of crowdfunding, - i.e. raising small amounts of funds from many individuals.', 'التنافسبية المالية هي منصة تمويل جماعي تربط المشاريع القائمة مع المستثمرين (المقترضين). تتبنى منصة التنافسية المالية أفضل التقنيات المالية لتقديم خدمات التمويل الجماعي خصوصاً تمويل المشاريع الصغيرة.', 9, 1, NULL, NULL, 'dsd', NULL, '2022-11-14 06:17:43', '2022-11-14 06:17:43', 0, 0),
(2, 'How can I know the times of offering opportunities?', 'How can I know the times of offering opportunities?', 'You can follow up on the offer of opportunities by visiting CFC platform, as well as if you are registered on the platform, you will be notified by e-mail periodically of the opportunities.', 'You can follow up on the offer of opportunities by visiting CFC platform, as well as if you are registered on the platform, you will be notified by e-mail periodically of the opportunities.', 9, 1, NULL, 1, NULL, NULL, '2022-11-14 06:42:38', '2022-11-14 06:42:38', 1, 0),
(3, 'What is meant by the term \'KYC\'?', 'What is meant by the term \'KYC\'?', 'The term KYC stands for “Know Your Customer” and is used throughout the client identification process. The pre-set KYC rules by Capital Market Authority (CMA) are the standard requirements that need to be followed by all regulated entities. This includes identity verification, proof of address, employment information, and other general information. Investors need to clear all KYC requirements prior to being onboarded on the CFC platform. The compliance department will conduct ongoing KYC checks to ensure information is constantly updated.', 'The term KYC stands for “Know Your Customer” and is used throughout the client identification process. The pre-set KYC rules by Capital Market Authority (CMA) are the standard requirements that need to be followed by all regulated entities. This includes identity verification, proof of address, employment information, and other general information. Investors need to clear all KYC requirements prior to being onboarded on the CFC platform. The compliance department will conduct ongoing KYC checks to ensure information is constantly updated.', 9, 1, NULL, 1, NULL, NULL, '2022-11-15 11:37:08', '2022-11-15 11:37:08', 1, 0),
(5, 'What measures are in place to ensure security around my data and the integrity of your platform?', 'What measures are in place to ensure security around my data and the integrity of your platform?', 'CFC Platform has been developed on our proprietary server. CFC Platform has leveraged the “best in breed” security features such as encryption, identity and access management, and network security. These features are applied across the whole platform from the holding of data, application access, web communications, and back office operations. We are committed to implement and continuously improve security-aware software development, operational management, and threat-mitigation practices that are essential to the strong protection of services and data', 'CFC Platform has been developed on our proprietary server. CFC Platform has leveraged the “best in breed” security features such as encryption, identity and access management, and network security. These features are applied across the whole platform from the holding of data, application access, web communications, and back office operations. We are committed to implement and continuously improve security-aware software development, operational management, and threat-mitigation practices that are essential to the strong protection of services and data', 9, 1, NULL, 1, NULL, NULL, '2022-11-21 07:28:52', '2022-11-21 07:28:52', 1, 0),
(6, 'What is Sukuk?', 'What is Sukuk?', 'Sukuk are securities issued by companies (or governments) to raise funds from investors for a specified period of time with a specified repayment date, during which period the sukuk usually distribute a profit rate (fixed or variable) periodically. At the end of the life of the instrument, known as the maturity period, the issuer of the security (the borrower) repays the capital raised from the investors.', 'Sukuk are securities issued by companies (or governments) to raise funds from investors for a specified period of time with a specified repayment date, during which period the sukuk usually distribute a profit rate (fixed or variable) periodically. At the end of the life of the instrument, known as the maturity period, the issuer of the security (the borrower) repays the capital raised from the investors.', 9, 1, NULL, 1, NULL, NULL, '2022-11-21 07:28:53', '2022-11-21 07:28:53', 1, 0),
(7, 'How do I make profit?', 'How do I make profit?', 'Each investment opportunity has a different distribution timing from the other, such as if it is quarterly, semi-annually, or paid in one payment, which is the maturity period at the end of the life of the instrument.', 'Each investment opportunity has a different distribution timing from the other, such as if it is quarterly, semi-annually, or paid in one payment, which is the maturity period at the end of the life of the instrument.', 9, 1, NULL, 1, NULL, NULL, '2022-11-21 07:28:54', '2022-11-21 07:28:54', 1, 0),
(8, '100% Shariah Compliance', '100٪ متوافق مع أحكام الشريعة', '.', '.', 8, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/sec9-1.svg', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fsec9-1.svg1670835756856?alt=media&token=0997ae21-d280-489a-a3d3-5f596881e565', '2022-11-21 07:28:56', '2022-11-21 07:28:56', 1, 0),
(9, 'Flexible Financing Terms', 'مرونه مدروسة لمدة التمويل', '.', '.', 8, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/sec9-2.svg', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fsec9-2.svg1670835973936?alt=media&token=81f852bc-f9d1-437e-aaa1-700b02b3c5b9', '2022-11-21 07:31:40', '2022-11-21 07:31:40', 1, 0),
(10, 'Financing as quick as 1 day', 'السرعه في اجراءات التمويل', '.', '.', 8, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/sec9-2.svg', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fsec9-2%20(1).svg1670836143408?alt=media&token=83a7e245-484c-4cb1-9671-ac2c47462d6b', '2022-11-21 07:31:42', '2022-11-21 07:31:42', 1, 0),
(11, 'Customised loans that fits your needs', 'تمويل بسمات مخصصة تناسب احتياجاتك', '.', '.', 8, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/sec9-3.svg', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fsec9-3.svg1670836217137?alt=media&token=4f4ac292-6654-4126-a0ba-a3cc8a075931', '2022-11-21 07:38:16', '2022-11-21 07:38:16', 1, 0),
(12, 'Enter Details', 'ادخال التفاصيل', 'Provide your contact information and login your account to start the process.', '<div style=\"direction: rtl;\">ادخل معلومات الاتصال الخاصه بك ثم قم بتسجيل الدخول في الحساب وابدأ العمليه.</div>', 5, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/sec3-1.svg', NULL, '2022-11-21 09:02:21', '2022-11-21 09:02:21', 1, 0),
(13, 'Verify by KYC', 'التحقق من البيانات', 'Provide your national ID number and your full name for the KYC verification purpose.', 'أدخل رقم هويتك الوطنية واسمك الكامل لغرض التحقق من بياناتك&nbsp;', 5, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/sec3-2.svg', NULL, '2022-11-21 09:02:23', '2022-11-21 09:02:23', 1, 0),
(14, 'Get Approval', 'الحصول على موافقة', 'Submit your KYC and personal details and get approval within 24hrs.', '<div style=\"\">بعد تقديم البيانات والتحقق منها ستحصل على الموافقة في غضون 24 ساعة</div>', 5, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/sec3-3.svg', NULL, '2022-11-21 09:02:24', '2022-11-21 09:02:24', 1, 0),
(15, 'Borrower', 'طالب التمويل', 'Planning to raise money for your business? Checkout our hassle free options for you.', '<div style=\"text-align: justify; direction: rtl;\"><span style=\"font-size: 1rem;\">هل تخطط لتمويل مشروعك؟ سجل بمنصة التنافسية المالية .</span></div>', 1, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fmoon.svg1670335059729?alt=media&token=c8a74faa-f2a1-41d4-a88c-31a195fe722c', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fmoon.svg1670335060987?alt=media&token=b0164e9c-993c-476d-8bc2-71fa575ec117', '2022-11-21 09:27:13', '2022-11-21 09:27:13', 1, 0),
(16, 'Investor', 'مستثمر', 'Invest in fast growing businesses with us.', '<div style=\"direction: rtl;\"><span style=\"font-size: 1rem;\">استثمر في أعمال سريعة النمو&nbsp;</span></div>', 1, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fmoon-2.svg1670335109298?alt=media&token=d27d7866-d96e-4896-b57e-7bc8fb96ecd7', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fmoon-2.svg1670335110226?alt=media&token=7af2a2cd-8ea8-4c58-8cba-496eb33e31af', '2022-11-21 09:27:14', '2022-11-21 09:27:14', 1, 0),
(17, 'General', 'معلومات عامة', 'Explore CFC website for info, suggestions and advise on crowdfunding and investment.', 'استكشف منصة التنافسية للحصول على معلومات واقتراحات ونصائح حول التمويل الجماعي والاستثمار', 1, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fmoon-3.svg1670335130416?alt=media&token=1632a28b-c6c9-4ddb-8b48-004be8c0d45a', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fmoon-3.svg1670335131434?alt=media&token=cb11d460-0c4b-4da0-8708-9e2950ebdf1a', '2022-11-21 09:27:16', '2022-11-21 09:27:16', 1, 0),
(18, 'What makes us different?', 'ما الذي يجعلنا مختلفين ؟', 'The Financial Competitiveness Team harnesses its expertise in the credit analysis of projects based on quantitative and qualitative analysis of the feasibility of the project and the company, its management and its financial statements, to reach the rating scale for investment risks. After that, the debt instrument, which is the sukuk, is issued, in which the investment is made.', '<p style=\"text-align: justify; direction: rtl;\"><span style=\"font-size: 1rem;\">يسخر فريق التنافسية المالية خبراته في التحليل الائتماني للمشاريع بناءً على التحليل الكمي والنوعي لجدوى المشروع والشركة وإدارتها وبياناتها المالية ، للوصول إلى مقياس تصنيف مخاطر الاستثمار. بعد ذلك يتم إصدار أداة الدين وهي الصكوك التي يتم الاستثمار فيها.</span></p>', 2, 1, NULL, NULL, NULL, NULL, '2022-11-21 09:35:01', '2022-11-21 09:35:01', 1, 0),
(19, '100% Shariah Compliance', '100٪ متوافق مع أحكام الشريعة', '.', '.', 3, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/feature-1.svg', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Ffeature-1%20(1).svg1670421215572?alt=media&token=c757f867-8ca1-4c97-8e33-ea4bddaaaf3f', '2022-11-21 09:37:58', '2022-11-21 09:37:58', 1, 0),
(20, 'Free promotion for your campaign', 'ترويج مجاني لحملتك', '.', '.', 3, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/feature-2.svg', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Ffeature-2.svg1670421230644?alt=media&token=747d1f7e-779d-4163-a5e4-877481507e6f', '2022-11-21 09:37:59', '2022-11-21 09:37:59', 1, 0),
(21, 'withdraw your amount instantly', 'السحب الفوري للمستحقات', '.', '.', 3, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/feature-3.svg', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Ffeature-3.svg1670421246060?alt=media&token=fd56d532-2e30-4167-9816-9d9515f56889', '2022-11-21 09:38:00', '2022-11-21 09:38:00', 1, 0),
(22, 'Competitiveness Financial Company (CFC) was established in September 2021, and the Competitiveness obtained a financial technology permit in securities business from the Capital Market Authority (CMA) in June 2022, to offer and invest in debt instruments.', 'تأسست شركة التنافسية المالية في سبتمبر 2021م، وحصلت التنافسية على تصريح التقنية المالية في أعمال الأوراق المالية​ من هيئة السوق المالية في يونيه 2022م، لطرح أدوات الدين والاستثمار فيها.', '<div style=\"text-align: justify;\"><span style=\"font-size: 1rem;\">Competitiveness Financial is an electronic platform for crowdfunding, which aims to connect investors with investment opportunities to finance projects, by arranging the issuance and offering of debt instruments to finance projects of small and medium-sized companies, which in turn contribute to raising the GDP and providing jobs, and presenting those opportunities in the platform to investors and clients Platform.\nCMA had launched the Financial Technology Lab in 2018, in order to keep pace with the accelerating technological revolution in the financial market. The financial technology system in the Kingdom is highly attractive, allowing companies to easily provide innovative services.\nCFC is one of the international technology competitiveness companies. It is a national institution that aims to provide integrated technical consultancy to government organizations and bodies and participate in restructuring systems and procedures to enhance access to the goals of the vision of the Kingdom of Saudi Arabia.</span></div>', '<p class=\"MsoNormal\" dir=\"RTL\" style=\"margin-right:18.0pt;text-align:justify;\nline-height:normal;direction:rtl;unicode-bidi:embed\"><span lang=\"AR-JO\" style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;;mso-ascii-font-family:Calibri;\nmso-ascii-theme-font:minor-latin;mso-hansi-font-family:Calibri;mso-hansi-theme-font:\nminor-latin;mso-bidi-font-family:Arial;mso-bidi-theme-font:minor-bidi;\nmso-bidi-language:AR-JO\">التنافسية المالية هي منصة إلكترونية للتمويل الجماعي،\nتهدف إلى وصل المستثمرين بالفرص الاستثمارية لتمويل المشاريع، من خلال ترتيب إصداروطرح\nأدوات الدين لتمويل مشاريع الشركات الصغيرة والمتوسطة، اﻟﺘﻲ ﺗﺴﺎﻫﻢ بدورها ﻓﻲ رﻓﻊ\nاﻟﻨﺎﺗﺞ اﻟﻤﺤﻠﻲ الإجمالي و ﺗﻮﻓﻴﺮ الوظائف، وعرض تلك الفرص في المنصة على المستثمرين\nعملاء المنصة.&nbsp;<o:p></o:p></span></p><p style=\"text-align: right; direction: rtl;\">\n\n</p><p class=\"MsoNormal\" dir=\"RTL\" style=\"margin-right:18.0pt;text-align:justify;\nline-height:normal;direction:rtl;unicode-bidi:embed\"><span lang=\"AR-JO\" style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;;mso-ascii-font-family:Calibri;\nmso-ascii-theme-font:minor-latin;mso-hansi-font-family:Calibri;mso-hansi-theme-font:\nminor-latin;mso-bidi-font-family:Arial;mso-bidi-theme-font:minor-bidi;\nmso-bidi-language:AR-JO\">ويقوم فريق عمل التنافسية المالية بتسخير خبراته في\nالتحليل الائتماني لمشاريع الشركات بناء على التحليل الكمي والتحليل النوعي لجدوى\nالمشروع والشركة وإدارتها وقوائمها المالية، للوصول إلى النطاق التصنيفي لمخاطر\nالاستثمار. بعد ذلك، يتم إصدار أداة الدين وهي الصكوك، التي يتم الاستثمار\nفيها.&nbsp; &nbsp;<o:p></o:p></span></p>', 4, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2FWhatsApp%20Image%202022-12-06%20at%207.13.49%20PM.jpeg1670336114330?alt=media&token=d37f5ea3-2fa8-404c-95b9-16d89686b61f', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2FWhatsApp%20Image%202022-12-06%20at%207.14.03%20PM.jpeg1670336117603?alt=media&token=d9a97cf8-d96c-48df-8fb7-999d4d079bb5', '2022-11-21 09:39:56', '2022-11-21 09:39:56', 1, 0),
(23, 'Ready to start your first Fund raise?', 'هل أنت جاهز لبدء طلب تمويلك ؟', 'Create and Register your account in CFC .', 'سجل حسابك على منصةالتنافسية', 6, 1, NULL, NULL, 'http://www.cfc.sa/assets/images/man.svg', NULL, '2022-11-22 06:12:01', '2022-11-22 06:12:01', 1, 0),
(24, 'Exceptional value', 'قيمة استثنائية', 'With competitiveness financial , you as an investor / borrower, deserve to be in our equation.', 'مع التنافسية المالية انت كمستثمر او طالب تمويل تستحق ان تكون في معادلتنا', 7, 1, NULL, NULL, NULL, NULL, '2022-12-08 10:38:48', '2022-12-08 10:38:48', 1, 0),
(25, 'How to start your fundraiser on Competitiveness Financial.', 'كيف تبدأ عملية التمويل على منصة التنافسية المالية', '', '', 5, 1, 1, NULL, NULL, NULL, '2022-12-08 10:40:42', '2022-12-08 10:40:42', 1, 0),
(26, 'Funding made simple & rewarding', 'أصبح التمويل بسيطًا ومجزٍ', '', '', 8, 1, 1, NULL, NULL, NULL, '2022-12-08 10:41:34', '2022-12-08 10:41:34', 1, 0),
(27, 'We promis to provide distingushed experience in investment and financing', 'نعد بتقديم تجربة متميزة في مجال الاستثمار و التمويل', 'through being innovative in providing technical financial solutions and gaining the trust of our investors and Partners.', 'من خلال إبتكارنا حلول في التقنية المالية وكسب ثقة المستثمرين والشركاء', 0, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fmain%20vedeo-with%20logo.mp41671455680295?alt=media&token=9bb3dd7b-c15b-41c6-bbe5-34cfd48ce5f7', 'https://firebasestorage.googleapis.com/v0/b/royal-stallion.appspot.com/o/Kyc%2Fmain%20vedeo-with%20logo.mp41671455691100?alt=media&token=c96c52a6-0d35-4fc9-aca9-97db0705172d', '2022-12-08 10:42:27', '2022-12-08 10:42:27', 1, 0);
