(1, '\"Welcome <b> {%users.name%} </b> <br><br> Thank you for Registering with Competitiveness Financial . on {%users.created_at%} <br><br>\\r\\nThanks <br>\\r\\n<b>Competitiveness Financial</b>\\r\\n\"', 1, 1, 'Registration', 'Your Registration is done.', '\"مرحبا بك <b> {%users.name%} </b> <br><br> لقد تم تسجيلك في منصة التنافسية  {%users.created_at%} <br><br>\\r\\nThanks <br>\\r\\n<b>التنافسية الماليةl</b>\\r\\n\"', 'تسجيل', 'تم تسجيلك بنجاح'),
(2, 'Hi <b> {%users.name%} </b> <br><br> Your Kyc has been Registered successfully with Ice Web. <br><br>\r\nThanks <br>\r\n<b>Ice Web</b>', 2, 1, 'Kyc Registration', 'Kyc Registration', NULL, NULL, NULL),
(3, 'Hi <b> {%users.name%} </b> <br><br> Your Kyc has been Rejected by Ice Web. <br><br>\r\nNote: {%users.kyc_note%} <br><br>\r\nThanks <br>\r\n<b>Ice Web</b>', 4, 1, 'Kyc Rejected', 'Kyc Status', NULL, NULL, NULL),
(4, 'Hi <b> {%users.name%} </b> <br><br> Your Kyc has been Accepted by Ice Web. <br><br>\r\nThanks <br>\r\n<b>Ice Web</b>', 3, 1, 'Kyc Accepted', 'Kyc Status', NULL, NULL, NULL),
(5, 'Hi <b> {%users.name%} </b> <br><br> Your Opportunity has been Approved by Ice Web. <br><br>\r\nThanks <br>\r\n<b>Ice Web</b>', 5, 1, 'Opportunity Approved', 'Opportunity Status', NULL, NULL, NULL),
(6, 'Hi <b> {%users.name%} </b> <br><br> Your Opportunity has been Rejected by Ice Web. <br><br>\r\nNote: {%campaigns.note%} <br><br>\r\nThanks <br>\r\n<b>Ice Web</b>', 6, 1, 'Opportunity Rejected', 'Opportunity Status', NULL, NULL, NULL),
(7, 'Hi <b> {%users.name%} </b> <br><br> Your Opportunity has been Successfully submitted. <br><br>\r\nThanks <br>\r\n<b>Ice Web</b>', 7, 1, 'Opprtunity Submission', 'Opprtunity Submission', NULL, NULL, NULL),
(8, 'Hi <b> {%users.name%} </b> <br><br> Congratulations, You have Successfully invested. <br><br>\r\nThanks <br>\r\n<b>Ice Web</b>', 8, 1, 'Investment Successfull', 'Investment Successfull', NULL, NULL, NULL),
(9, '\"Welcome <b> {%users.name%} </b> <br><br> Thank you for Registering with Competitiveness Financial . on {%users.created_at%} <br><br>\\r\\nThanks <br>\\r\\n<b>Competitiveness Financial</b>\\r\\n\"', 3, 1, 'QAZQee', 'QAZQ', '\"مرحبا بك <b> {%users.name%} </b> <br><br> لقد تم تسجيلك في منصة التنافسية  {%users.created_at%} <br><br>\\r\\nThanks <br>\\r\\n<b>التنافسية الماليةl</b>\\r\\n\"', 'QAZQ', 'QAZQ'),
(10, '\"Hi <b> {%users.name%} </b> <br><br> Thank you for Registering with Ice Web. on {%users.created_at%} <br><br>\\r\\nThanks <br>\\r\\n<b>Ice Web</b>\\r\\n\"', 1, 2, 'ASDFG', 'ASDFG', '\"Hi <b> {%users.name%} </b> <br><br> Thank you for Registering with Ice Web. on {%users.created_at%} <br><br>\\r\\nThanks <br>\\r\\n<b>Ice Web</b>\\r\\n\"', 'ASDFG', 'ASDFG'),
