INSERT INTO `pages` (`id`, `title`, `ar_title`, `description`, `ar_description`, `status`, `position`, `created_at`, `updated_at`) VALUES
(1, 'Privacy Policy', 'إشعار الخصوصية', 'إشعار الخصوصية\r\nيصف إشعار الخصوصية هذا كيف شركة التنافسية المالية )يشار إليها فيما بعد باسم \"الشركة\"(، تجمع البيانات الشخصية\r\nوكيفية معالجتها واستخدامها وحمايتها داخل المملكة العربية السعودية.\r\nتعريفات :\r\nأ. في إشعار الخصوصية هذا، ما لم يقت ِض السياق خالف ذلك، إن المصطلحات التالية المشار إليها لها المعاني التالية:\r\n• الكيان التابع: تعني أي كيان تكون فيه الشركة في هذا الكيان داخل المملكة العربية السعودية.\r\n• البيانات الشخصية: تعني البيانات التي قد تؤدي إلى تحديد هوية الشخص، بشكل مباشر أو غير مباشر، بما في ذلك\r\nعلى سبيل المثال ال الحصر: االسم األول واالسم األخير أو العائلة ورقم الهوية الوطنية السعودية والعناوين ورقم\r\nالهاتف ورقم الحساب المصرفي ورقم البطاقة االئتمانية.\r\nب. اإلشارة إلى \" الشركة\" أو \" نحن\" أو \" لنا \"، بشكل فردي وجماعي، تشمل جميع الفروع والمكاتب والشركات الفرعية\r\nوالشركات التابعة ألي من أعضاء المجموعة التي تجمع وتستخدم بياناتك الشخصية داخل المملكة العربية السعودية.\r\nالبيانات الشخصية التي نجمعها:\r\nتختلف البيانات التي نجمعها بنا ًء على الغرض من استخدامها. ومع ذلك، فيما يلي أمثلة على البيانات التي نجمعها:\r\n• البيانات التي يتم جمعها من خالل نماذج الطلبات أو االستتتبيانات أو غيرها من الوثائو أو االتصتتاالت. على ستتبيل\r\nالمثال ال الحصر االسم الكامل وتاريخ الميالد وأرقام الهوية.\r\n• بيانات عن معامالتك ومنتجاتك معنا، مثل نشاط الحساب واستخدام المنتجات.\r\n• البيتانتات التي يتم جمعهتا من خالل استتتتتختدامتك لختدمتاتنتا أو موقعنتا اإللكتروني أو تطبيقتات الهواتف المحمولت ة )مثتل\r\nملفات تعريف االرتباط(.\r\n• البيتانات التي يتم تبتادلهتا أثنتاء تواصتتتتلنتا معتك، مثتل طلبتات خدمة العمالء والمرئيتات التي تصتتتتلنتا منتك إما من خالل\r\nموقعنا اإللكتروني أو تطبيقات الهاتف المحمول أو حستتابات وستتائل التواصتتل االجتماعي أو أي قنوات نستتتخدمها\r\nللتواصل مع العمالء.\r\nاألساس القانوني وأغراض جمع واستخدام بياناتك الشخصية:\r\nوفقا بناء على طبيعة الخدمات واألعمال. في معظم الحاالت، يتضمن أساسنا ً نقوم بجمع واستخدام البيانات لما هو متطلب\r\nالقانوني وأغراضنا، على سبيل المثال ال الحصر:\r\n• االمتثال ألية التزامات ومتطلبات صادرة عن الجهات القانونية والتنظيمية داخل المملكة العربية السعودية.\r\n• السماح لنا بتقديم المنتجات أو الخدمات.\r\n• لحمايتك من االحتيال عن طريو إجراء عمليات التحقو من الهوية واالئتمان أو التحقو من عدم وجود تعارض.\r\n• تحسين منتجاتنا وخدماتنا وتجربتك المقدمة عبر قنواتنا.\r\n• فهم احتياجاتك كعميل وأهليتك للمنتجات والخدمات.\r\n• الترويج لمنتجات وخدمات استثمارية ومالية جديدة قد تهمك.\r\n\r\nكيف يتم جمع بياناتك الشخصية :\r\nهناك العديد من نقاط االتصال التي تساعدنا في جمع بياناتك، وبعض األمثلة:\r\n• عند انشاء العالقة واالستفادة من الخدمة - عندما تستخدم خدماتنا وتصبح عميالً وتستفيد من منتجاتنا.\r\n• تبادل المعلومات - عند إكمال نموذج ورفعه على موقعنا اإللكتروني أو تطبيقات الهاتف المحمول أو البريد اإللكتروني\r\nأو منشورات وسائل التواصل االجتماعي أو عبر االتصال بمركز العمالء أو المشاركة في الحمالت الترويجية.\r\n• التفاعل )وسائل التواصل االجتماعي( - أي منشورات أو تفاعل أو تواصل تجريها معنا بشكل مباشر على قنوات\r\nالتواصل االجتماعي.\r\n• نمط التصفح - بيانات حول كيفية استكشافك لموقعنا على االنترنت ، وتوقيت زيارتك، وأنواع متصفح اإلنترنت، وكيف\r\nتمت إحالتك إلى موقعنا.\r\n• االستطالعات - استطالعات الويب عبر اإلنترنت التي تمكننا من جمع اآلراء بشأن المواضيع. مثل، ما يعجبك وما ال\r\nيعجبك بشأن شكل ومظهر موقعنا اإللكتروني وتطبيقات األجهزة المحمولة. مالحظاتك القيمة تمكننا من تحسين جودة\r\nالتجربة التي نقدمها لك كمنظمة.\r\nأو من وكيلك المعتمد أومن ممثلك القانوني.\r\n• منك شخصياً\r\n• في الحاالت المقبولة قانونياً، من أطراف ثالثة ومصادر عامة. وهذا يشمل الجهات الحكومية وشركات ووكاالت\r\nالمعلومات االئتمانية.\r\nتخزين بياناتك الشخصية:\r\nستكون بياناتك الشخصية:\r\n• محتفظ بها طالما كان ذلك ضروريًا لتحقيو الغرض الذي تم جمعها من أجله.\r\n• محتفظ بها داخل المملكة العربية السعودية.\r\n• محتفظ بها لتلبية أي متطلبات قانونية وتنظيمية.\r\nحماية بياناتك الشخصية:\r\nنحن نضمن حماية بياناتك بشكل مناسب من خالل استخدام اإلجراءات واالحتياطات األمنية المادية والتقنية واإلدارية واإلجرائية\r\nالالزمة لمنع الوصول غير المصرح به أو الجمع أو االستخدام أو الكشف أو النسخ أو التعديل أو التخلص منها. نحمي بياناتك\r\nبطريقة تتوافو مع أنظمة ولوائح حماية البيانات ذات العالقة السارية بها في المملكة العربية السعودية. ومع ذلك، فإن اإلنترنت\r\nليس آمنًا بشكل كامل.\r\nاإلفصاح عن بياناتك الشخصية:\r\nأ. قد نشارك بيناتك مع أي من األطراف المذكورة أدناه:\r\n1 .أي محكمة أو أي جهة حكومية أو تنظيمية لالمتثال ألي التزامات ومتطلبات صادرة عن جهات قانونية وتنظيمية\r\nداخل المملكة العربية السعودية.\r\n2 .أي وكيل تحصيل ديون أو جهة مرخصة بتقديم خدمة المعلومات االئتمانية أو شركة تأمين.\r\n3 .أي مزود خدمة مرتبط بالشركة بغرض تزويدك بالمنتجات أو الخدمات، وتحسين منتجاتنا وخدماتنا وتجربتك\r\nعبر قنواتنا، والترويج لمنتجات وخدمات االستثمار المالي الجديدة التي قد تهمك.\r\nب. قد يتم التواصل معك و/أو إرسال إشعارات إليك عبر قنوات مختلفة مثل الرسائل القصيرة ) SMS )و/أو البريد\r\nاإللكتروني و/أو الهاتف فيما يتعلو بمنتجاتنا وخدماتنا.\r\n\r\nالتغييرات على إشعار الخصوصية\r\nنحتفظ بالحو في تعديل إشعار الخصوصية هذا في أي وقت. يشير تاريخ نفاذ إشعار الخصوصية، كما هو مذكور أدناه، إلى\r\nأحدث تاريخ تمت فيه مراجعة إشعار الخصوصية هذا أو تعديله. يتيح لك التحقو من تاريخ النفاذ أدناه تحديد ما إذا كانت هناك\r\nتغييرات منذ آخر مرة قمت فيها بمراجعة إشعار الخصوصية. لذلك، ننصحك بالتحقو بشكل دوري على إشعار الخصوصية\r\nهذا لضمان اطالعك على النسخة المحدثة.\r\nاستخدام ملفات تعريف االرتباط\r\nمن أجل تحسين تجربة عمالئنا، يستخدم موقعنا اإللكتروني تقنية قياسية تسمى \"ملفات تعريف االرتباط\" لجمع معلومات حول\r\nكيفية استخدام موقعنا اإللكتروني ، والتي قد تتضمن بياناتك. يعد استخدام ملفات تعريف االرتباط أمًرا ضروريًا لتشغيل موقعنا\r\nاإللكتروني.\r\nاتصل بنا\r\nفي حالة وجود أي أسئلة، يمكنك التواصل معنا من خالل أي من المقر الرئيسي للشركة، والبريد اإللكتروني، والمحادثة الفورية،\r\nووسائل التواصل االجتماعي أو من خالل موقعنا اإللكتروني وتطبيو الهاتف المحمول.\r\nتاريخ النفاذ\r\nتم تعديل هذا اإلشعار بتاريخ 2022.01\r\nإخالء مسئولية\r\nال يهدف إشعار الخصوصية هذا إلى إنشاء أي حقوق تعاقدية من أي نوع أو أي حقوق قانونية أخرى، أو ينشئ أي التزامات\r\nعلينا فيما يتعلو بأي طرف آخر أو نيابة عن أي طرف. عندما تقوم بتسجيل الدخول إلى مواقع االنترنت الخاصة بأي طرف\r\nثالث، لن يسري إشعار الخصوصية هذا. إضافة إلى ذلك، نحن لسنا مسؤولين عن محتوى مواقع الويب الخاصة بأي طرف\r\nثالث وال نمثل أي طرف ثالث. ل ذلك، نوصيك بمراجعة سياسة الخصوصية واألمان لكل رابط تقوم بتسجيل الدخول إليه .', 'إشعار الخصوصية', 1, 1, '2022-10-26 09:56:06', '2022-12-02 15:00:53'),
(2, 'Investment Agency Agreement', 'اتفاقية وكالة بالاستثمار', '<b>{%users.name%}</b>\r\n\r\nالسعودية\r\n اتفاقية وكالة بالاستثمار\r\n مقدمة الحمد لله، والصلاة والسلام على نبينا محمد، وعلى آله وصحبه، وبعد ُ إنه في يوم هـ الموافق - ابرمت هذه الاتفاقية بين كل من:\r\n شركة التنافسية المالية وهي شركة قائمة بموجب قوانين المملكة العربية السعودية، وعنوان مقرها الرئيسي: المملكــة العربيــة الســعودية، مدينــة الريــاض طريــق ------ حــي ----، ص. ب. -----، وهــي شركــة مصـرحة مـن قبـل هيئـة السـوق الماليـة لإنشـاء منصـة طـرح أدوات الـدين والاسـتثمار فيهـا فـي مختـبر التقنيـة المالية. ويُشار إليها في هذه الاتفاقية بـــــــــ(الشركة). السيد <b> {%users.name%} </b> (سعودي) ، رقم هوية ------- بتاريخ 00-00-0000 ،وعنوانه الرئيسي: المملكة العربية السعودية، مدينة الرياض، حي: ------ ويُشار إليه في هذه الاتفاقية بـــــــــ(الطرف الثاني-العميل، المو ِّكل-المستثمر). ويُشار إلى الطرف الأول والطرف الثاني مجتمعين فيما بعد بـــــــ(الطرفان-الطرفين) التمهيد حيث إن الطرف الأول شركة مصرحة من قبل هيئة السوق المالية لإنشاء منصة طرح أدوات الدين والاستثمار فيها في مختبر التقنية المالية، ومتوافقة مع الأنظمة المعمول بها في المملكة العربية السعودية، وحيث يرغب الطرف الثاني في استثمار أمواله من خلال منصة إصدار الصكوك التي يديرها الطرف الأول وفق شروط وأحكام هذه الاتفاقية. لذا فقد اتفق الطرفان وهما بكامل أهليتهما المعتبرة شر ًعا ونظا ًما على الدخول في هذه الاتفاقية التي تحدد شروط وأحكام اتفاقية الوكالة بالاستثمار، وذلك على النحو الآتي\r\n المادة الأولى:\r\n حجية المقدمة والتمهيد والملاحق تُعد المقدمة والتمهيد أعلاه جز ًء لها ا لا يتجزأ من هذه ا لاتفاقية ومتممةً المادة الثانية: محل الاتفاقية و َّكل المستثمُر بموجب هذه الاتفاقية الشركةَ /الصكوك المملوكة للمستثمر في شراء سلع قابلة للتسييل وبيعها باستثمار القيمة الاسمية للصك مرابحة للمستفيد باسم الشركة ولصالح المستثمر ونيابة أحكــام ومبــادئ الشريعــة الإسلاميــة، كمــا يخــول ً عنه، وبما لا يتعــارض مــع بممارســة جميــع الحقــوق والسلطات والصلاحيات الأخرى ذات العلاقة، والتي من بينها تحصيل مبلغ الاستثمار من المســتثمُر الشركــةَ ً المستفيد، ورفع عنه، وذلك ليتمكن من الوفاء بالتزاماته الناشئة بموجب الدعاوى نيابة هذه الاتفاقية، وقبل الطرف الأول ذلك.\r\n المادة الثالثة:\r\n طبيعة النشاط الاستثماري وإدارته:\r\n 1 .اتفـق الطرفـان علـى أن يُقيَّـد نشـاط الاسـتثمار فـي عمليـات تمويـل مرابحـة بالآجـل مـع المسـتفيد باسـتخدام حصيلة الاكتتاب في الصكوك، وذلك من خلال منصة إصدار الصكوك، وذلك في أي إصدار متاح على الموقع الإلكتروني للشركة يحدده العميل. ويكون التمويل بالآجل من للمسـتفيد، ولا يحـق للشركـة التصـرف بمبلـغ الاسـتثمار فـي غيـر النشـاط المنصـوص خلال قيام الشركة بشراء سلع وبيعها بالآجل مرابحـةً عليـه فـي هـذه الاتفاقية.\r\n 2 .تتعهد الشركة للمستثمر بموجب هذه الاتفاقية أنها ستدير مبلغ الاستثمار بالكفاءة والعناية اللازمة، وذلك وفقً الائتمانية المعتمدة لدى الشركة. ا للسياسات \r\n3 .للشركة الحرية المطلقة دون الرجوع للمستثمر في اتخاذ الإجراءات اللازمة للاستثمار، بما في ذلك: توقيع العقــود، والتفــاوض مــع الآخريــن، ودفــع قيمــة العمليــات والمصــاريف اللازمــة لتنفيذهــا، وتحصــيل المبــالغ ودفعها، وأية إجراءات أخرى يتطلبها استثمار أموال كل الصلاحيات إلى طرف آخر إذا دعت الحاجة لذلك، ووفقً . المستثمر، وللشركة.\r\nالحق في إسناد وتفويض بعض أو ا لتقديرها المطلق \r\n4 .اتفق الطرفان بأَّنه ليس للمو ِّكل الحق في مراجعة الوكيل لإلزامه ببعض الأعمال، أو اشتراط أخذ موافقة الموكل على بعض التصرفات بعد التوقيع على هذه الاتفاقية، كما لا يحق للمو ِّكل التواصل مع المستفيد لإلزامه بالدفع أو رفع دعوى قضائية أو أي إجراءات أخرى دون الرجوع للوكيل.\r\n 5 .اتفق الطرفان بأ َّن للوكيل الحق المطلق في التواصل مع المستفيد والمستثمرين الآخرين المشاركين في إصدار الصكوك، وليس للمو ِّكل الحق في مراجعة المستثمرين الآخرين أو المستفيد. المادة الرابعة: مبلغ الاستثمار\r\n 1 .علـى المسـتثمر إيـداع رأس المـال فـي حسـابه الاسـتثماري \"حسـاب المسـتثمر الافتراضـي\" المسـجل فـي صفحته الشخصية على الموقع الإلكتروني للمنصة. \r\n2 .وافـق المسـتثمر علـى أنـه يجـوز للشركـة دمـج مبلـغ الاسـتثمار مـع أمـوال الشركـة والأمـوال الأخـرى التـي تتسلمها الشركة من المستثمرين الآخرين من وقت لآخر. المادة الخامسة: مدة الاستثمار ٍّي من الطرفين، فيما يتعلق بأي إصدار صـكوك قـائم ومسـتحق قب ًرا على حقوق والتزامات أ يجب ألا يكون إنهاء الاتفاقية أو انتهائها مؤث ـل ِّ انتهـاء هـذه الاتفاقيـة، حيـث سـتظل شـروط وأحكـام هـذه الاتفاقيـة ساريـة حتـى الانتهاء من تسوية الصكوك القائمة. المادة السادسة: أجرة الشركة اتفق الطرفان على أ َّن الشركة تستحق رسو ًما مقابل عملها نيابة الربح الفعلي، تُحددها الشركة في ً عن المستثمر تق َّدر بنسبة مئوية من صافي النشرة الخاصة بكل إصدار. المادة السابعة: عوائد الصكوك ا لما هو معلن عنه في نشرة الإصدار 1 .يتعهد الوكيل بعد استلام مبالغ التوزيعات الدورية المحددة في جدول السداد الخاص بالإصدار وفقً الخاصة بالإصدار. وذلك من المستفيد بإيداع المبلغ في حساب المستثمر بعد خصم أجرة الوكيل أو أي مصاريف تتعلق بالتحصيل والمحاماة. 2 .في حال حصول خسارة في إصدار الصكوك فيتعهد الوكيل بإعادة ما تبقى من مبلغ الاستثمار إلى المو ِّكل، وذلك مع مراعاة ما ورد في الفقرة الثانية للمادة التاسعة بعد خصم كافة مصاريف التحصيل والمحاماة 3 .فــي حــال الســداد المبكــر فيتــم إعــادة احتســاب العائــد المســتحق للمســتثمر بنــا ًء علــى التــاريخ الفعلــي للسداد. المادة الثامنة: نطاق المسؤولية: 1 .يقر المستثمر ويعي كامل المخاطر الناشئة عن عمليات التمويل من خلال المنصة، واحتمال خسارة كامل مبلغ الاستثمار أو جزء منه. 2 .يقر المو ِّكل بأن الوكيل أمين على مبلغ الاستثمار وإدارته، لا يضمنه في ذمته ما لم يتعد أو يفرط أو يخالف شروط هذه الاتفاقية، وعليه فقد وافق المو ِّكل بأن حدود المسؤولية القانونية للوكيل ومديريه وموظفيه عن الخسائر أو التكاليف أو الأضرار مهما كانت طبيعتها أو المطالبات أو المصروفات لأي سبب كان، بما في ذلك الأتعاب القانونية، لا تتجاوز بحال من الأحوال مقدار مبلغ الاستثمار المدفوع للوكيــل بمــوجب هــذه الاتفاقيــة، علــى أن لا يتــم تعــويض المو ِّكــل إلا بمــوجب حكــم قضــائي مكتســب القطعية. 3 .فــي حــال الســداد المبكــر فيتــم إعــادة احتســاب العائــد المســتحق للمســتثمر بنــا ًء علــى التــاريخ الفعلــي للسداد. 4 .في حال حصول خسارة -لا قدر الله- في إصدار الصكوك فإن الخسارة تو َّزع على جميع المستثمرين في الإصدار بحسب حصة كل طرف في إجمالي حصيلة الاكتتاب، ولا يحق للشركة مطالبة المستثمر بأي تعويض عن جهده وعمله في هذه الحال. المادة التاسعة: عدم ممارسة الحقوق: 1 .لا يُعــد عــدم قيــام الطــرف الأول أو تــأخره بالمطالبــة بحقــوقه أو ممارســته لأي حــق مــن حقــوقه الناشئــة بموجب هذه الاتفاقية تنازًلا من جهته، ويحق للطرف الأول أن يتخذ كافة الإجراءات التي تكفل له تحصيل حقوقه من الطرف الثاني في أي وقت. ِّي خسائر أو أضرار يتعرض لها الطرف الثاني بسبب ممارسة أو عدم ممارسة الطرف الأول لأي 2 .لن يكون الطرف الأول مسؤو ًلا عن أ من حقوقه الناشئة عن هذه الاتفاقية أو الاتفاقيات المرتبطة بها. 3 .فــي حــال الســداد المبكــر فيتــم إعــادة احتســاب العائــد المســتحق للمســتثمر بنــا ًء علــى التــاريخ الفعلــي للسداد. المادة العاشرة: تحويل الحقوق: 1 .وافــق الطــرف الثــاني علــى أ َّن للطــرف الأول الحــق فــي التنــازل أو تحويل كــل أو بعــض حقــوقه والتزامــاته الناتجـة عـن هـذه الاتفاقيـة والاتفاقيـات المرتبطـة بهـا إلـى مـن يشـاء دون توقـف ذلـك علـى رضـا الطـرف الثاني. 2 .لا يحق للطرف الثاني أن يتنازل عن كل أو بعض أو أن يحول التزاماته المترتبة عليه بموجب هذه الاتفاقية إلى أي جهة أخرى دون موافقة خطية مسبقة من الطرف الأول. المادة الحادية عشرة: النظام واجب التطبيق وتسوية المنازعات ا للأنظمة واللوائح المعمول بها في المملكة العربية السعودية وبما لا يخالف أحكام ومبادئ الشريعة 1 .تخضع هذه الاتفاقية وتفسر وفقً الإسلامية. ذر ذلك فيتم حله عن 2 .كل خلاف ينشأ بين الطرفين حول تفسير أو تنفيذ هذه الاتفاقية أو أي بند من بنودها يتم حله بالطرق الودية، فإذا تعَّ طريق اللجوء إلى الجهات القضائية المختصة في المملكة العربية السعودية، بمدينة الرياض. المادة الثانية عشرة: أحكام عا َّمة: 1 .تسـري الأحكـام والشـروط الـواردة فـي هـذه الاتفاقيـة علـى أطرافهـا الموضحـة بيانـاتهم فـي صـدرها، كمـا تسـري علـى خلفـائهم الشرعييـن والقـانونيين، وبمـا لا يتعـارض أو يخـالف الأحكـام والشـروط الـواردة فـي اتفاقية فتح الحساب على الموقع الإلكتروني للشركة. 2 .يقــر الطرفــان بأنهمــا قــد اطلعــا علــى كافــة بنــود هــذه الاتفاقيــة ومــا يرتبــط بهــا مــن اتفاقيــات، وفهمــا محتوياتها، وأنهم ملتزمون بكل ما ورد فيها من شروط وأحكام. َّي حكم من أحكام هذه الاتفاقية مخالف للأنظمة المعمول بها أو أصبح كذلك بموجب أي نظام أو حكم قضائي فإن البطلان يرد 3 .إذا تبين أن أ على ذلك الحكم أو الشرط، ولا يؤثر ذلك على سريان باقي الأحكام والشروط الواردة في الاتفاقية. 4 .يتم تنفيذ العمليات خلال أيام وأوقات العمل الرسمية، ولا تدخل أيام العطل والإجازات الرسمية ضمن أيام العمل هذه. 5 .في حالة وفاة الموكل فلورثته الحق في إمضاء الوكالة أو فسخها بموجب إشعار خطي للوكيل، على أن تُراعى الأحكام الواردة المادة السادسة من هذه الاتفاقية. 6 .يــدرك ويقــر المو ِّكــل أَّنــه فــي حــال تــم التحقــق أو الاشتبــاه بــأي عمليــة متعلقــة بغســل الأمــوال وتمويــل الإرهــاب، فســيتم إيقــاف الحســاب الاســتثماري مؤقتًــا أو بشكــل دائــم، وفــق ســياسات الإبلاغ عــن تلــك الواقعة، وذلك بموجب نظام مكافحة غسل الأموال الصادر بالمرسوم الملكي رقم (م/20 (عام 1439ه، ونظـام مكافحـة الإرهـاب وتمـويله الصـادر بـالمرسوم الملكـي رقـم (م/21 (وتـاريخ 1439/02/12هــ، واللائحـة التنفيذية لنظام مكافحة الإرهاب وتمويله الصادرة بقرار مجلس الوزراء رقم (228 (وتاريخ 1440/05/02هـ، ونظام مكافحة جرائم المعلوماتية : الصادر بالمرسوم الملكي رقم (م/17 (عام 1428هـ. : الإخطارات والمراسلات:المادة الثالثة عشرة العناوين المبينة بصدر هذه الاتفاقية لكل طرف هي عنوانه النظامي، وتتم جميع المراسلات من طلبات أو إشعارات أو إقرارات أو موافقات أو أي مستندات أخرى عن طريقها، أو عن طريق البريد المسجل أو الفاكس أو البريد الإلكتروني أو تسلم باليد أو بأي طريقة من الطرق المعتمدة لدى الطرف الأول، وتعد المراسلات التي تتم عن طريق هذه العناوين ُملزمة للطرف الثاني، ولا يُعتد بأي تغيير لهذه العناوين إلا بموجب خطاب كتابي سابق إلى موجه إلى الطرف الأول. ملحق: التعريفات يقصد بالعبارات التالية أينما وردت في هذه الاتفاقية 1\" .اتفاقية الوكالة بالاستثمار\": علاقة تعاقدية بين مو ِّكل ووكيل يقوم المو ِّكل بموجبها بتعيين الوكيل للقيام بأعمال محددة نيابة عنه، وفٍقا لما جاء في التمهيد والمادة الثالثة من هذه الاتفاقية، في مقابل أجرة محددة يدفعها الموكل للوكيل 2\" .أجرة الوكيل\": نسبة مئوية من صافي الربح الفعلي للإصدار.، وذلك مقابل قيام الوكيل بإدارة الإصدار على منصة إصدار الصكوك. 3“ .إجمـالي حصـيلة الاكتتـاب\": مجمـوع المبـالغ المسـتلمة مـن المسـتثمرين فـي المنصـة، للاسـتثمار فـي إصـدار صكوك المرابحة. 4“ .إصـدار الصـكوك\": اسـتثمار ُمعلـن عنـه مـن قبـل الشركـة، مـن خلال منصـة إصـدار الصـكوك، ويقـوم إصـدار الصكوك على أساس عملية مرابحة متوافقة مع أحكام الشرعية الإسلامية. 5\" .التاريخ الفعلي للسداد\": هو التاريخ الذي يتعدى تاريخ الاستحقاق المعلن عنه في إصدار الصكوك. 6\" .السداد المبكر\": هي عملية تسديد كامل المبلغ من قبل المستفيد قبل تاريخ الاستحقاق. 7“ .العائـد المسـتحق\": العائـد المسـتحق للموكـل بحسـب حصـته فـي إجمـالي ربـح التمويـل النـاتج عـن الصـفقة الاستثمارية بالنظر إلى إجمالي حصيلة الاكتتاب. 8\" .المستثمرون\": الأشخاص الراغبون بالاستثمار في الصكوك المطروحة من خلال منصة إصدار الصكوك. 9\" .المستفيد\": العميل المتمول من حصيلة الاكتتاب في الصكوك بموجب عقد المرابحة. ا لما هو معلن في نشرة الإصدار المتاحة على الموقع 10\" .تاريخ الاستحقاق\": تاريخ سداد ثمن البيع المؤجل في حسابات وكيل الدفع وفقً الإلكتروني للمنصة. 11\" .تاريخ التوزيع الدوري\": هو عملية إيداع المبالغ المستحقة في حسابات المستثمرين خلال (5 (خمسة أيام عمل من تاريخ إيداع أي قسط مح َّصل من ثمن البيع المؤجل من قبل المستفيد في حسابات وكيل الدفع. 12\" .حساب المستثمر الافتراضي\": حساب مالي إلكتروني، يقر المستخدم بموجبه بأنه ليس حسابًا مصرفيًا ولا يوفر الخدمات المصرفية غير التي تنص عليها اتفاقية فتح الحساب على الموقع الإلكتروني للمنصة. 13\" .صافي الربح الفعلي\": مقدار الربح الحقيقي الذي تم تحقيقه من الصكوك. ا لشروط وأحكام هذه الاتفاقية في صكوك 14\" .مبلغ الاستثمار\": المبلغ الذي يود الطرف الثاني استثماره وفقً إسلامية خلال المنصة. 15\" .معَّدل الربح المتوقع\": معدل الربح الذي يتوقع المستثمر استلامه في تاريخ التوزيع الدوري، والمعلن من قبل مسؤول المنصة على منصة إصدار الصكوك. 16\" .نشرة الإصدار:\" ملف المعلومات الرئيسة لكل فرصة استثمارية معلن عنها في الموقع الالكتروني. 17 .صكوك المرابحة: هي وثائق متساوية القيمة يتم إصدارها لتمويل شراء سلعة المرابحة وبيعها للمستفيد، ويمثل الصك حصة شائعة في ملكية سلعة المرابحة بعد شرائها وقبل بيعها وتسليمها لمشتريها وفي ثمنها بعد بيعها للمستفيد، وعائد هذه الصكوك هو الفرق بين ثمن شراء سلعة المرابحة وثمن بيعها للمستفيد. 18\" .القيمة الاسمية للصك:\" ثمن بيع الصك للمستثمر والمعلن عنه في نشرة الإصدار. 19 .منصة إصدار الصكوك )المنصة): المنصة الإلكترونية لشركة التنافسية المالية المتاحة للاستعمال من خلال الموقع الإلكتروني والتي تقدم من خلالها شركة التنافسية المالية خدمات إصدار الصكوك 20 .وكيل حملة الصكوك/الوكيل: شركة التنافسية المالية.\r\n', '<b>{%users.name%}</b>\r\n\r\nالسعودية\r\n اتفاقية وكالة بالاستثمار\r\n مقدمة الحمد لله، والصلاة والسلام على نبينا محمد، وعلى آله وصحبه، وبعد ُ إنه في يوم هـ الموافق - ابرمت هذه الاتفاقية بين كل من:\r\n شركة التنافسية المالية وهي شركة قائمة بموجب قوانين المملكة العربية السعودية، وعنوان مقرها الرئيسي: المملكــة العربيــة الســعودية، مدينــة الريــاض طريــق ------ حــي ----، ص. ب. -----، وهــي شركــة مصـرحة مـن قبـل هيئـة السـوق الماليـة لإنشـاء منصـة طـرح أدوات الـدين والاسـتثمار فيهـا فـي مختـبر التقنيـة المالية. ويُشار إليها في هذه الاتفاقية بـــــــــ(الشركة). السيد <b> {%users.name%} </b> (سعودي) ، رقم هوية ------- بتاريخ 00-00-0000 ،وعنوانه الرئيسي: المملكة العربية السعودية، مدينة الرياض، حي: ------ ويُشار إليه في هذه الاتفاقية بـــــــــ(الطرف الثاني-العميل، المو ِّكل-المستثمر). ويُشار إلى الطرف الأول والطرف الثاني مجتمعين فيما بعد بـــــــ(الطرفان-الطرفين) التمهيد حيث إن الطرف الأول شركة مصرحة من قبل هيئة السوق المالية لإنشاء منصة طرح أدوات الدين والاستثمار فيها في مختبر التقنية المالية، ومتوافقة مع الأنظمة المعمول بها في المملكة العربية السعودية، وحيث يرغب الطرف الثاني في استثمار أمواله من خلال منصة إصدار الصكوك التي يديرها الطرف الأول وفق شروط وأحكام هذه الاتفاقية. لذا فقد اتفق الطرفان وهما بكامل أهليتهما المعتبرة شر ًعا ونظا ًما على الدخول في هذه الاتفاقية التي تحدد شروط وأحكام اتفاقية الوكالة بالاستثمار، وذلك على النحو الآتي\r\n المادة الأولى:\r\n حجية المقدمة والتمهيد والملاحق تُعد المقدمة والتمهيد أعلاه جز ًء لها ا لا يتجزأ من هذه ا لاتفاقية ومتممةً المادة الثانية: محل الاتفاقية و َّكل المستثمُر بموجب هذه الاتفاقية الشركةَ /الصكوك المملوكة للمستثمر في شراء سلع قابلة للتسييل وبيعها باستثمار القيمة الاسمية للصك مرابحة للمستفيد باسم الشركة ولصالح المستثمر ونيابة أحكــام ومبــادئ الشريعــة الإسلاميــة، كمــا يخــول ً عنه، وبما لا يتعــارض مــع بممارســة جميــع الحقــوق والسلطات والصلاحيات الأخرى ذات العلاقة، والتي من بينها تحصيل مبلغ الاستثمار من المســتثمُر الشركــةَ ً المستفيد، ورفع عنه، وذلك ليتمكن من الوفاء بالتزاماته الناشئة بموجب الدعاوى نيابة هذه الاتفاقية، وقبل الطرف الأول ذلك.\r\n المادة الثالثة:\r\n طبيعة النشاط الاستثماري وإدارته:\r\n 1 .اتفـق الطرفـان علـى أن يُقيَّـد نشـاط الاسـتثمار فـي عمليـات تمويـل مرابحـة بالآجـل مـع المسـتفيد باسـتخدام حصيلة الاكتتاب في الصكوك، وذلك من خلال منصة إصدار الصكوك، وذلك في أي إصدار متاح على الموقع الإلكتروني للشركة يحدده العميل. ويكون التمويل بالآجل من للمسـتفيد، ولا يحـق للشركـة التصـرف بمبلـغ الاسـتثمار فـي غيـر النشـاط المنصـوص خلال قيام الشركة بشراء سلع وبيعها بالآجل مرابحـةً عليـه فـي هـذه الاتفاقية.\r\n 2 .تتعهد الشركة للمستثمر بموجب هذه الاتفاقية أنها ستدير مبلغ الاستثمار بالكفاءة والعناية اللازمة، وذلك وفقً الائتمانية المعتمدة لدى الشركة. ا للسياسات \r\n3 .للشركة الحرية المطلقة دون الرجوع للمستثمر في اتخاذ الإجراءات اللازمة للاستثمار، بما في ذلك: توقيع العقــود، والتفــاوض مــع الآخريــن، ودفــع قيمــة العمليــات والمصــاريف اللازمــة لتنفيذهــا، وتحصــيل المبــالغ ودفعها، وأية إجراءات أخرى يتطلبها استثمار أموال كل الصلاحيات إلى طرف آخر إذا دعت الحاجة لذلك، ووفقً . المستثمر، وللشركة.\r\nالحق في إسناد وتفويض بعض أو ا لتقديرها المطلق \r\n4 .اتفق الطرفان بأَّنه ليس للمو ِّكل الحق في مراجعة الوكيل لإلزامه ببعض الأعمال، أو اشتراط أخذ موافقة الموكل على بعض التصرفات بعد التوقيع على هذه الاتفاقية، كما لا يحق للمو ِّكل التواصل مع المستفيد لإلزامه بالدفع أو رفع دعوى قضائية أو أي إجراءات أخرى دون الرجوع للوكيل.\r\n 5 .اتفق الطرفان بأ َّن للوكيل الحق المطلق في التواصل مع المستفيد والمستثمرين الآخرين المشاركين في إصدار الصكوك، وليس للمو ِّكل الحق في مراجعة المستثمرين الآخرين أو المستفيد. المادة الرابعة: مبلغ الاستثمار\r\n 1 .علـى المسـتثمر إيـداع رأس المـال فـي حسـابه الاسـتثماري \"حسـاب المسـتثمر الافتراضـي\" المسـجل فـي صفحته الشخصية على الموقع الإلكتروني للمنصة. \r\n2 .وافـق المسـتثمر علـى أنـه يجـوز للشركـة دمـج مبلـغ الاسـتثمار مـع أمـوال الشركـة والأمـوال الأخـرى التـي تتسلمها الشركة من المستثمرين الآخرين من وقت لآخر. المادة الخامسة: مدة الاستثمار ٍّي من الطرفين، فيما يتعلق بأي إصدار صـكوك قـائم ومسـتحق قب ًرا على حقوق والتزامات أ يجب ألا يكون إنهاء الاتفاقية أو انتهائها مؤث ـل ِّ انتهـاء هـذه الاتفاقيـة، حيـث سـتظل شـروط وأحكـام هـذه الاتفاقيـة ساريـة حتـى الانتهاء من تسوية الصكوك القائمة. المادة السادسة: أجرة الشركة اتفق الطرفان على أ َّن الشركة تستحق رسو ًما مقابل عملها نيابة الربح الفعلي، تُحددها الشركة في ً عن المستثمر تق َّدر بنسبة مئوية من صافي النشرة الخاصة بكل إصدار. المادة السابعة: عوائد الصكوك ا لما هو معلن عنه في نشرة الإصدار 1 .يتعهد الوكيل بعد استلام مبالغ التوزيعات الدورية المحددة في جدول السداد الخاص بالإصدار وفقً الخاصة بالإصدار. وذلك من المستفيد بإيداع المبلغ في حساب المستثمر بعد خصم أجرة الوكيل أو أي مصاريف تتعلق بالتحصيل والمحاماة. 2 .في حال حصول خسارة في إصدار الصكوك فيتعهد الوكيل بإعادة ما تبقى من مبلغ الاستثمار إلى المو ِّكل، وذلك مع مراعاة ما ورد في الفقرة الثانية للمادة التاسعة بعد خصم كافة مصاريف التحصيل والمحاماة 3 .فــي حــال الســداد المبكــر فيتــم إعــادة احتســاب العائــد المســتحق للمســتثمر بنــا ًء علــى التــاريخ الفعلــي للسداد. المادة الثامنة: نطاق المسؤولية: 1 .يقر المستثمر ويعي كامل المخاطر الناشئة عن عمليات التمويل من خلال المنصة، واحتمال خسارة كامل مبلغ الاستثمار أو جزء منه. 2 .يقر المو ِّكل بأن الوكيل أمين على مبلغ الاستثمار وإدارته، لا يضمنه في ذمته ما لم يتعد أو يفرط أو يخالف شروط هذه الاتفاقية، وعليه فقد وافق المو ِّكل بأن حدود المسؤولية القانونية للوكيل ومديريه وموظفيه عن الخسائر أو التكاليف أو الأضرار مهما كانت طبيعتها أو المطالبات أو المصروفات لأي سبب كان، بما في ذلك الأتعاب القانونية، لا تتجاوز بحال من الأحوال مقدار مبلغ الاستثمار المدفوع للوكيــل بمــوجب هــذه الاتفاقيــة، علــى أن لا يتــم تعــويض المو ِّكــل إلا بمــوجب حكــم قضــائي مكتســب القطعية. 3 .فــي حــال الســداد المبكــر فيتــم إعــادة احتســاب العائــد المســتحق للمســتثمر بنــا ًء علــى التــاريخ الفعلــي للسداد. 4 .في حال حصول خسارة -لا قدر الله- في إصدار الصكوك فإن الخسارة تو َّزع على جميع المستثمرين في الإصدار بحسب حصة كل طرف في إجمالي حصيلة الاكتتاب، ولا يحق للشركة مطالبة المستثمر بأي تعويض عن جهده وعمله في هذه الحال. المادة التاسعة: عدم ممارسة الحقوق: 1 .لا يُعــد عــدم قيــام الطــرف الأول أو تــأخره بالمطالبــة بحقــوقه أو ممارســته لأي حــق مــن حقــوقه الناشئــة بموجب هذه الاتفاقية تنازًلا من جهته، ويحق للطرف الأول أن يتخذ كافة الإجراءات التي تكفل له تحصيل حقوقه من الطرف الثاني في أي وقت. ِّي خسائر أو أضرار يتعرض لها الطرف الثاني بسبب ممارسة أو عدم ممارسة الطرف الأول لأي 2 .لن يكون الطرف الأول مسؤو ًلا عن أ من حقوقه الناشئة عن هذه الاتفاقية أو الاتفاقيات المرتبطة بها. 3 .فــي حــال الســداد المبكــر فيتــم إعــادة احتســاب العائــد المســتحق للمســتثمر بنــا ًء علــى التــاريخ الفعلــي للسداد. المادة العاشرة: تحويل الحقوق: 1 .وافــق الطــرف الثــاني علــى أ َّن للطــرف الأول الحــق فــي التنــازل أو تحويل كــل أو بعــض حقــوقه والتزامــاته الناتجـة عـن هـذه الاتفاقيـة والاتفاقيـات المرتبطـة بهـا إلـى مـن يشـاء دون توقـف ذلـك علـى رضـا الطـرف الثاني. 2 .لا يحق للطرف الثاني أن يتنازل عن كل أو بعض أو أن يحول التزاماته المترتبة عليه بموجب هذه الاتفاقية إلى أي جهة أخرى دون موافقة خطية مسبقة من الطرف الأول. المادة الحادية عشرة: النظام واجب التطبيق وتسوية المنازعات ا للأنظمة واللوائح المعمول بها في المملكة العربية السعودية وبما لا يخالف أحكام ومبادئ الشريعة 1 .تخضع هذه الاتفاقية وتفسر وفقً الإسلامية. ذر ذلك فيتم حله عن 2 .كل خلاف ينشأ بين الطرفين حول تفسير أو تنفيذ هذه الاتفاقية أو أي بند من بنودها يتم حله بالطرق الودية، فإذا تعَّ طريق اللجوء إلى الجهات القضائية المختصة في المملكة العربية السعودية، بمدينة الرياض. المادة الثانية عشرة: أحكام عا َّمة: 1 .تسـري الأحكـام والشـروط الـواردة فـي هـذه الاتفاقيـة علـى أطرافهـا الموضحـة بيانـاتهم فـي صـدرها، كمـا تسـري علـى خلفـائهم الشرعييـن والقـانونيين، وبمـا لا يتعـارض أو يخـالف الأحكـام والشـروط الـواردة فـي اتفاقية فتح الحساب على الموقع الإلكتروني للشركة. 2 .يقــر الطرفــان بأنهمــا قــد اطلعــا علــى كافــة بنــود هــذه الاتفاقيــة ومــا يرتبــط بهــا مــن اتفاقيــات، وفهمــا محتوياتها، وأنهم ملتزمون بكل ما ورد فيها من شروط وأحكام. َّي حكم من أحكام هذه الاتفاقية مخالف للأنظمة المعمول بها أو أصبح كذلك بموجب أي نظام أو حكم قضائي فإن البطلان يرد 3 .إذا تبين أن أ على ذلك الحكم أو الشرط، ولا يؤثر ذلك على سريان باقي الأحكام والشروط الواردة في الاتفاقية. 4 .يتم تنفيذ العمليات خلال أيام وأوقات العمل الرسمية، ولا تدخل أيام العطل والإجازات الرسمية ضمن أيام العمل هذه. 5 .في حالة وفاة الموكل فلورثته الحق في إمضاء الوكالة أو فسخها بموجب إشعار خطي للوكيل، على أن تُراعى الأحكام الواردة المادة السادسة من هذه الاتفاقية. 6 .يــدرك ويقــر المو ِّكــل أَّنــه فــي حــال تــم التحقــق أو الاشتبــاه بــأي عمليــة متعلقــة بغســل الأمــوال وتمويــل الإرهــاب، فســيتم إيقــاف الحســاب الاســتثماري مؤقتًــا أو بشكــل دائــم، وفــق ســياسات الإبلاغ عــن تلــك الواقعة، وذلك بموجب نظام مكافحة غسل الأموال الصادر بالمرسوم الملكي رقم (م/20 (عام 1439ه، ونظـام مكافحـة الإرهـاب وتمـويله الصـادر بـالمرسوم الملكـي رقـم (م/21 (وتـاريخ 1439/02/12هــ، واللائحـة التنفيذية لنظام مكافحة الإرهاب وتمويله الصادرة بقرار مجلس الوزراء رقم (228 (وتاريخ 1440/05/02هـ، ونظام مكافحة جرائم المعلوماتية : الصادر بالمرسوم الملكي رقم (م/17 (عام 1428هـ. : الإخطارات والمراسلات:المادة الثالثة عشرة العناوين المبينة بصدر هذه الاتفاقية لكل طرف هي عنوانه النظامي، وتتم جميع المراسلات من طلبات أو إشعارات أو إقرارات أو موافقات أو أي مستندات أخرى عن طريقها، أو عن طريق البريد المسجل أو الفاكس أو البريد الإلكتروني أو تسلم باليد أو بأي طريقة من الطرق المعتمدة لدى الطرف الأول، وتعد المراسلات التي تتم عن طريق هذه العناوين ُملزمة للطرف الثاني، ولا يُعتد بأي تغيير لهذه العناوين إلا بموجب خطاب كتابي سابق إلى موجه إلى الطرف الأول. ملحق: التعريفات يقصد بالعبارات التالية أينما وردت في هذه الاتفاقية 1\" .اتفاقية الوكالة بالاستثمار\": علاقة تعاقدية بين مو ِّكل ووكيل يقوم المو ِّكل بموجبها بتعيين الوكيل للقيام بأعمال محددة نيابة عنه، وفٍقا لما جاء في التمهيد والمادة الثالثة من هذه الاتفاقية، في مقابل أجرة محددة يدفعها الموكل للوكيل 2\" .أجرة الوكيل\": نسبة مئوية من صافي الربح الفعلي للإصدار.، وذلك مقابل قيام الوكيل بإدارة الإصدار على منصة إصدار الصكوك. 3“ .إجمـالي حصـيلة الاكتتـاب\": مجمـوع المبـالغ المسـتلمة مـن المسـتثمرين فـي المنصـة، للاسـتثمار فـي إصـدار صكوك المرابحة. 4“ .إصـدار الصـكوك\": اسـتثمار ُمعلـن عنـه مـن قبـل الشركـة، مـن خلال منصـة إصـدار الصـكوك، ويقـوم إصـدار الصكوك على أساس عملية مرابحة متوافقة مع أحكام الشرعية الإسلامية. 5\" .التاريخ الفعلي للسداد\": هو التاريخ الذي يتعدى تاريخ الاستحقاق المعلن عنه في إصدار الصكوك. 6\" .السداد المبكر\": هي عملية تسديد كامل المبلغ من قبل المستفيد قبل تاريخ الاستحقاق. 7“ .العائـد المسـتحق\": العائـد المسـتحق للموكـل بحسـب حصـته فـي إجمـالي ربـح التمويـل النـاتج عـن الصـفقة الاستثمارية بالنظر إلى إجمالي حصيلة الاكتتاب. 8\" .المستثمرون\": الأشخاص الراغبون بالاستثمار في الصكوك المطروحة من خلال منصة إصدار الصكوك. 9\" .المستفيد\": العميل المتمول من حصيلة الاكتتاب في الصكوك بموجب عقد المرابحة. ا لما هو معلن في نشرة الإصدار المتاحة على الموقع 10\" .تاريخ الاستحقاق\": تاريخ سداد ثمن البيع المؤجل في حسابات وكيل الدفع وفقً الإلكتروني للمنصة. 11\" .تاريخ التوزيع الدوري\": هو عملية إيداع المبالغ المستحقة في حسابات المستثمرين خلال (5 (خمسة أيام عمل من تاريخ إيداع أي قسط مح َّصل من ثمن البيع المؤجل من قبل المستفيد في حسابات وكيل الدفع. 12\" .حساب المستثمر الافتراضي\": حساب مالي إلكتروني، يقر المستخدم بموجبه بأنه ليس حسابًا مصرفيًا ولا يوفر الخدمات المصرفية غير التي تنص عليها اتفاقية فتح الحساب على الموقع الإلكتروني للمنصة. 13\" .صافي الربح الفعلي\": مقدار الربح الحقيقي الذي تم تحقيقه من الصكوك. ا لشروط وأحكام هذه الاتفاقية في صكوك 14\" .مبلغ الاستثمار\": المبلغ الذي يود الطرف الثاني استثماره وفقً إسلامية خلال المنصة. 15\" .معَّدل الربح المتوقع\": معدل الربح الذي يتوقع المستثمر استلامه في تاريخ التوزيع الدوري، والمعلن من قبل مسؤول المنصة على منصة إصدار الصكوك. 16\" .نشرة الإصدار:\" ملف المعلومات الرئيسة لكل فرصة استثمارية معلن عنها في الموقع الالكتروني. 17 .صكوك المرابحة: هي وثائق متساوية القيمة يتم إصدارها لتمويل شراء سلعة المرابحة وبيعها للمستفيد، ويمثل الصك حصة شائعة في ملكية سلعة المرابحة بعد شرائها وقبل بيعها وتسليمها لمشتريها وفي ثمنها بعد بيعها للمستفيد، وعائد هذه الصكوك هو الفرق بين ثمن شراء سلعة المرابحة وثمن بيعها للمستفيد. 18\" .القيمة الاسمية للصك:\" ثمن بيع الصك للمستثمر والمعلن عنه في نشرة الإصدار. 19 .منصة إصدار الصكوك )المنصة): المنصة الإلكترونية لشركة التنافسية المالية المتاحة للاستعمال من خلال الموقع الإلكتروني والتي تقدم من خلالها شركة التنافسية المالية خدمات إصدار الصكوك 20 .وكيل حملة الصكوك/الوكيل: شركة التنافسية المالية.\r\n', 1, 1, '2022-11-01 07:09:37', '2023-01-17 11:54:44');
INSERT INTO `pages` (`id`, `title`, `ar_title`, `description`, `ar_description`, `status`, `position`, `created_at`, `updated_at`) VALUES
(3, 'Terms & Conditions', 'الشروط و الأحكام', 'اﻟﺸﺮوط واﻟﺄﺣﻜﺎم\r\nالتمهيد:\r\nلما كانت شركة التنافسية المالية تقوم بتقديم خدمات التقنية المالية في أعمال الأوراق المالية بموجب التصريح الصادر لها بذلك من قبل هيئة السوق المالية ـ يشار إليها فيما بعد بـ «الشركة»، ولما كان العميل يرغب في فتح حساب وفق النظم والضوابط والإجراءات المتبعة لدى الشركة بغرض الاستفادة من الخدمات والمنتجات التي تقدمها لعملائها والمتعاملين معها، وحيث اطلع العميل على بنود وأحكام هذه الاتفاقية بعناية والتي توضح تفاصيل الخدمة التي تقدمها شركة التنافسية المالية وتحدد الالتزامات والحقوق بين التنافسية المالية والعميل، فقد اتفق الطرفان (الشركة والعميل) وهما بكامل الأهلية والصفة المعتبرة شرعاً مع خلوهما من الموانع الشرعية والنظامية على إبرام هذه الاتفاقية وفق شروطها وأحكامها الآتية:\r\nالمادة الأولى: التعريفات:\r\n1.	التنافسية المالية: شركة التنافسية المالية الحاصلة على تصريح تجربة التقنية المالية في أعمال الأوراق المالية من هيئة السوق المالية، ذات السجل التجاري رقم (1010818020) وتاريخ 12/01/1444هـ، ومقرها بمدينة الرياض.\r\n2.	العميل: هو الشخص الطبيعي أو الاعتباري المستفيد من خدمات منصة التنافسية المالية.\r\n3.	المنصة: هي المنصة الإلكترونية لشركة التنافسية المالية والتي تقدم من خلال الموقع الإلكتروني خدمات إصدار أدوات الدين والاستثمار فيها للمنشآت طالبة التمويل.\r\n4.	مخاطر إعسار المصدر: هي خطر إعسار الشريك -الشركة- ويؤدي ذلك إلى إفلاس حملة الصكوك إلى خسارة كلية.\r\n5.	مخاطر التأرجح: هي سوء تصرف الموظفين أو الأعضاء مما ينتج عنه بشكل مباشر أو غير مباشر وتؤدي إلى الإعسار.\r\n6.	مخاطر عدم توزيع الاستثمار: هي عدم تحقيق المستثمر أي تنويع في المحفظة الاستثمارية، ويمكن تجنيبها بتوزيع مبالغ الاستثمار على شركات متعددة.\r\n7.	صعوبة التخارج: هي ظروف خاصة لقابلية التخارج ولا توجد سوق ثانوية لتداول الصكوك في هذه اللحظة.\r\n8.	نظام مكافحة جرائم المعلوماتية: الصادر بالمرسوم الملكي رقم (م/17) عام 1428هـ.\r\n9.	نظام مكافحة غسل الأموال: الصادر بالمرسوم الملكي رقم (م/20) عام 1439هـ.\r\n10.	الهيئة: تعني هيئة السوق المالية بالمملكة العربية السعودية.\r\n11.	حساب العميل: يعني حساب العميل الاستثماري أو حساباته الاستثمارية لدى الشركة بالريال السعودي والمخصصة لتنفيذ القيود النقدية المقابلة لعمليات الاستثمار\r\n12.	تعليمات العميل: تعني جميع الأوامر والتعليمات والطلبات النظامية والمشروعة المبلغة و/أو المسلمة منه للشركة بشأن أية عملية من عمليات الاستثمار والخدمات الأخرى التي تقدمها له الشركة وفق الإجراءات والعقود والاتفاقيات المنظمة لها.\r\n\r\nالمادة الثانية: التعريف بالمنصة:\r\n1.	هي منصة عبر الإنترنت تمكن المستخدمين من الوصول إلى العروض المقدمة من قبل الشركات المدرجة في المنصة من خلال إصدار أدوات الدين والاستثمار بها، والاستثمار فيها على أساس اتفاقية استثمار، ولهذا الغرض تنشر الشركات معلوماتها عبر المنصة.\r\n2.	في حالة الاستثمار من قبل المستخدمين لا تصبح التنافسية المالية طرفًا متعاقدًا بنفسها، ويبرم الاستثمار فقط بين المستخدمين والشركة المستثمر بها.\r\n3.	يجب على الشركة المصدرة التي تقدم دعوتها للمستخدمين لتقديم عروضهم بناء على حملة إصدار الصكوك توفير المعلومات الخاصة بالاستثمار الجماعي على منصة التنافسية المالية.\r\n4.	لا تتحمل التنافسية المالية مدى مصداقية البيانات التي تقدمها الشركة المصدرة.\r\n5.	تسعى التنافسية المالية لتطوير خدماتها باستمرار، مما قد يستدعي في بعض الأحيان بإلغاء الخدمة مؤقتا أو بشكل دائم.\r\n6.	يسري استخدام المنصة داخل المملكة العربية السعودية فقط.\r\n\r\nالمادة الثالثة: المشغل والمزود للمنصة:\r\nشركة التنافسية المالية هي المشغل والمزود لمنصة التنافسية المالية، والخدمة المقدمة تخضع لشروط التنافسية المالية التالية التي يجب أن تطبق في النسخة السارية وقت تسجيل المستخدم.\r\n\r\nالمادة الرابعة: التسجيل:\r\n1.	يجب التسجيل كمستخدم في بعض أقسام منصة التنافسية المالية.\r\n2.	يدخل المستخدم في عقد استخدام مع شركة التنافسية المالية بمجرد التسجيل.\r\n3.	تقوم التنافسية المالية– في بعض الأحيان – بالتحقق من المستخدم باستخدام خدمة \"يقين\" المقدمة من \"علم\".\r\n4.	يجب على المستخدم أن يكون ذا أهلية وقدرة كافية على التعاقد.\r\n5.	يجب تقديم كافة البيانات المطلوبة من الأفراد أو المنشآت للتنافسية المالية خلال عملية التسجيل، ويتحمل المستخدم المسؤولية الكاملة حال إدخاله البيانات غير الصحيحة خلال عملية التسجيل أو أي مرحلة من مراحل استخدام خدمات المحفظة.\r\n6.	يجب على العميل تقديم أي معلومات إضافية للتثبت من هويته أو لإثبات موثوقية أي أداة تمويل يسجلها المستخدم لاستخدامها مع التنافسية المالية.\r\n7.	يجوز للتنافسية المالية أو طرف ثالث تتعاقد معه القيام بكافة التحريات التي تراها ضرورية للتحقق من المعلومات التي يتم تقديمها للتنافسية المالية، على سبيل المثال لا الحصر: فحص قواعد البيانات التجارية أو التقارير الائتمانية.\r\n8.	لا تضمن التنافسية المالية ما يجري أثناء اتخاذ إجراءات التحقق من هوية المستخدم.\r\n9.	يجب على المستخدم تصحيح بياناته فورا في حال تغيرها أو إدخالها بشكل غير كامل أو غير صحيح.\r\n10.	يجب على المستخدم التأكد من سرية كلمة المرور.\r\n11.	يجب إبلاغ التنافسية المالية فورا للاستخدام غير المصرح لكلمة المرور أو حساب المستخدم.\r\n12.	لا يجوز استخدام الحساب لغير المستخدم سواء كان ذلك الشخص طبيعيًا أو معنويًا.\r\n13.	تكون اتفاقية المستخدم واجبة على الطرفين من خلال النقر على رابط التأكيد المرسل عبر البريد الإلكتروني للمستخدم.\r\n14.	تكون مدة اتفاقية المستخدم غير محددة بوقت معين.\r\n15.	يحق للتنافسية المالية أو للمستخدم إنهاء اتفاقية المستخدم بأي وقت دون إشعار مسبق منها على سبيل المثال: حذف حساب المستخدم.\r\n16.	تطبق جميع حدود المسؤولية والتعويضات في هذه الاتفاقية، حتى بعد إنهاء اتفاقية العميل .\r\n17.	تقدم الشركة خدماتها ومنتجاتها للعميل حسب تصنيفه وتنفذ أوامره وتعليماته المشروعة ذات العلاقة وفقاً لأحكام هذه الاتفاقية\r\n\r\nالمادة الخامسة: اتفاق الوكالة بالاستثمار:\r\n1.	يجب على العميل تعبئة النماذج على منصة التنافسية المالية والنقر على زر \"استثمر\" نهاية النموذج.\r\n2.	يقر العميل بقبول الاستثمار في الشركة المصدرة ووفقًا لشروطها.\r\n3.	يجب بلوغ الحد الأدنى لمبلغ الاستثمار للجولة والمتفق عليه مع الشركة المصدرة سلفًا لكي تكون اتفاقية الاستثمار نافذة.\r\n4.	يجوز إبرام عقد مكتوب بالإضافة إلى الإجراء المذكور أعلاه.\r\n5.	يلتزم العميل باتفاق الاستثمار دون أي مطالبة بإبرام اتفاقية استثمار مستقلة.\r\n6.	تلتزم الشركة بالمدة المحددة لعرض الاستثمارات على منصة التنافسية المالية.\r\n7.	تلتزم التنافسية المالية بتزويد كافة الأطراف المتعاقدة بالبيانات اللازمة للتواصل مع الطرف الآخر.\r\n8.	تلتزم التنافسية المالية بإرسال جميع المستندات إلكترونيًا من خلال البريد الإلكتروني العميل .\r\n9.	يتحمل العميل المسؤولية بكافة المستندات المرسلة من تلقاء نفسه بشكل إلكتروني أو مادي.\r\n10.	عملاً بنص لوائح هيئة السوق المالية يلزم على الشركة الاحتفاظ بأموال العميل في حساب باسمه لدى أحد البنوك المحلية ويوافق العميل على أحقية التنافسية المالية بالحصول على جميع العوائد والأرباح العائدة من الاحتفاظ بأموال العملاء في هذه الحسابات. \r\n11.	تقوم الشركة بناءً على تعليمات العميل بتنفيذ جميع العمليات المتعلقة بالاستثمار على أساس نقدي من خلال حسابه الاستثماري.\r\n12.	إذا ما حدث خطأ غير مقصود من جانب الشركة أو خلل بنظامها الآلي أدى إلى إضافة أي مبلغ لحساب العميل الاستثماري دون وجه حق أو تمكينه من الاستثمار على المكشوف، فإن العميل يقر بأن المبلغ أصبح مديونية ويلتزم بتغطية مديونية حسابه الاستثماري في موعد أقصاه يوم العمل التالي. \r\n\r\nالمادة السادسة: حدود المسؤولية:\r\n1.	تتحمل التنافسية المالية المسؤولية نتيجة الإهمال الجسيم أو  إذا فشلت في الوفاء بواجب يكون الوفاء به ضروريًا لأداء العقد على النحو الصحيح والذي يمكن أن يعتمد على الطرف المتعاقد الآخر – الواجب الأساسي –.\r\n2.	في كل الأحوال الأخرى لا يكون الطرفان مسؤولين عن أي أضرار من أي نوع بغض النظر عن موضوع المطالبة بما في ذلك المسؤولية عن العقد.\r\n3.	في حال بطلان اتفاقية الوكالة بالاستثمار تقتصر المطالبات المحتملة للمستخدم ضد التنافسية المالية الناتجة عن هذه الحقيقة على استرداد مبلغ الاستثمار فقط.\r\n4.	لا تتحمل التنافسية المالية أي مسؤولية إضافية على ما ذكر أعلاه، منها الحالات الآتية: خصائص الخدمات أو الأضرار المستحقة وفقا لحدود المسؤولية للمنتج أو الأضرار الناجمة عن فقدان الحياة أو الإصابة الجسدية أو الأضرار بالصحة.\r\n5.	تشمل المسؤولية موظفي التنافسية المالية والوكلاء المباشرين والأطراف الثالثة الأخرى التي تستخدمها التنافسية المالية للوفاء بالعقد.\r\n6.	يحق للشركة أن ترفض تنفيذ أية عمليات أو تعليمات للعميل إذا رأت وفق تقديرها المطلق أن الرصيد الدائن بحسابه الاستثماري لا يكفي لذلك أو لن يكون كافياً في تاريخ تنفيذ العملية.\r\n\r\nالمادة السابعة: المخاطر العامة:\r\nيرتبط الاستثمار بالشركات الناشئة بمخاطر عالية، وقد يؤدي إلى الخسارة الكاملة لاستثمارك. يجب ألا تستثمر الأموال التي لا يمكنك تحمل خسارتها، وفي حال الخسارة يُقتصر على المبلغ المستثمر فقط. الاستثمار من خلال التنافسية المالية هو استثمار طويل الأجل ومناسب للمستثمرين على المدى الطويل. إن فرص الاستثمار في الوقت الحالي مخصصة للأشخاص المقيمين في المملكة العربية السعودية\r\n1.	يقر العميل بعلمه واطلاعه على المخاطر المصاحبة بالاستثمار في صكوك الشركات الناشئة والمصدرة بمنصة التنافسية المالية وأن أي دخل يتحقق منها، يمكن أن ينخفض أو يرتفع وأنه من المحتمل أن تنخفض قيمتها لتصبح دون مستوى الاستثمارات الأصلية.\r\n2.	يقر العميل بعلمه واطلاعه  بأن الاستثمار طويل الأجل، وذلك من خلال تقييم الفرص وإجمالي مخاطر الخسارة ومخاطر الإعسار ومخاطر التأرجح ومخاطر عدم توزيع الاستثمار وصعوبة التخارج والمخاطر المرتبطة بأنشطة الاستثمار والالتزامات أو التنبؤات حول الأداء المستقبل.\r\n3.	تلتزم التنافسية المالية بدورها في المنصة، ولا تقدم خدمات أعمال الاستشارة.\r\n4.	تلتزم الشركات المصدرة بصحة البيانات المقدمة، وتخلي التنافسية المالية مسؤوليتها عن مدى مصداقية البيانات.\r\n5.	لا تضمن التنافسية المالية التوقعات المستقبلية للتطوير الناجح التي تقدمها الشركات المصدرة، ويتحمل العميل كافة القرارات الاستثمارية بشكل مستقل ويتحمل أي مخاطر مستقبلية.\r\n6.	للعميل وحده الخيار في الاستثمار في الشركة المطروحة أم لا.\r\n7.	يجب على العميل الاطلاع على كافة العواقب النظامية والاقتصادية والضريبية ذات الصلة بالاستثمار قبل الاستثمار وأثناء فترة الاحتفاظ.\r\n8.	يقر ويتعهد العميل بالتزامه بنظام السوق المالية ولوائحه التنفيذية، وتعليمات تصريح تجربة التقنية المالية، والأنظمة واللوائح الأخرى المعمول بها في المملكة لا سيما نظام جرائم الإرهاب وتمويله ونظام مكافحة غسل الأموال ولائحته التنفيذية وأي تحديثات تطرأ على ما سبق من وقت لأخر.\r\n\r\nالمادة الثامنة: السرية والإفصاح والخصوصية:\r\n1.	السرية: يتعين على الشركة أن تحافظ على سرية معلومات العميل بما في ذلك بياناته لديها والمعلومات التي حصلت عليها منه وتعاملاته معها وعدم إفشائها أو الإفصاح عنها للغير والاستثناء من ذلك إذا كان الإفصاح عنها مطلوباً عملاً بأحكام نظام السوق المالية ولوائحه التنفيذية أو أية أنظمة أخرى مرعية ذات علاقة أو إذا كان ذلك ضرورياً لتنفيذ عملية أو أداء خدمة للعميل أو إذا وافق العميل على ذلك صراحة.\r\n2.	يقر العميل بأنه قد اطلع على الاتفاقية والملاحق والنماذج المرفقة بها، وإشعار الخصوصية المنشور على الرابط التالي (https://www.cfc.sa/privacy-policy)، ومع الإقرار المسبق بأن كافة هذه النماذج والملاحق هي عرضة للتعديل أو الحذف أو الإضافة كليا أو جزئياً من وقت لأخر وتفهمها جيداً وقبل بها جزءاً لا يتجزأ من هذه الاتفاقية وأنه مسؤول عن صحة واكتمال وسريان مفعول ودقة بيانات حقولها وما تضمنته من معلومات والتزامه بإرفاق وتسليم المستندات والوثائق الثبوتية المؤيدة والمؤكدة لذلك.\r\n3.	يقر العميل بأنه يلزم عليه أخذ الحيطة والحذر في تعاملاته الإلكترونية والمحافظة على كلمة المرور وعدم إفشائها لأي شخص كان بمن فيهم موظفي الشركة وأنه لا يحق له الرجوع على الشركة أو مطالبتها بأية خسائر أو أضرار قد تلحق به جراء إفصاحه أو معرفة الغير لكلمة المرور وتنفيذ أي عملية بموجبه وبتحمله منفرداً كافة التبعات.\r\n\r\n', 'اﻟﺸﺮوط واﻟﺄﺣﻜﺎم\r\nالتمهيد:\r\nلما كانت شركة التنافسية المالية تقوم بتقديم خدمات التقنية المالية في أعمال الأوراق المالية بموجب التصريح الصادر لها بذلك من قبل هيئة السوق المالية ـ يشار إليها فيما بعد بـ «الشركة»، ولما كان العميل يرغب في فتح حساب وفق النظم والضوابط والإجراءات المتبعة لدى الشركة بغرض الاستفادة من الخدمات والمنتجات التي تقدمها لعملائها والمتعاملين معها، وحيث اطلع العميل على بنود وأحكام هذه الاتفاقية بعناية والتي توضح تفاصيل الخدمة التي تقدمها شركة التنافسية المالية وتحدد الالتزامات والحقوق بين التنافسية المالية والعميل، فقد اتفق الطرفان (الشركة والعميل) وهما بكامل الأهلية والصفة المعتبرة شرعاً مع خلوهما من الموانع الشرعية والنظامية على إبرام هذه الاتفاقية وفق شروطها وأحكامها الآتية:\r\nالمادة الأولى: التعريفات:\r\n1.	التنافسية المالية: شركة التنافسية المالية الحاصلة على تصريح تجربة التقنية المالية في أعمال الأوراق المالية من هيئة السوق المالية، ذات السجل التجاري رقم (1010818020) وتاريخ 12/01/1444هـ، ومقرها بمدينة الرياض.\r\n2.	العميل: هو الشخص الطبيعي أو الاعتباري المستفيد من خدمات منصة التنافسية المالية.\r\n3.	المنصة: هي المنصة الإلكترونية لشركة التنافسية المالية والتي تقدم من خلال الموقع الإلكتروني خدمات إصدار أدوات الدين والاستثمار فيها للمنشآت طالبة التمويل.\r\n4.	مخاطر إعسار المصدر: هي خطر إعسار الشريك -الشركة- ويؤدي ذلك إلى إفلاس حملة الصكوك إلى خسارة كلية.\r\n5.	مخاطر التأرجح: هي سوء تصرف الموظفين أو الأعضاء مما ينتج عنه بشكل مباشر أو غير مباشر وتؤدي إلى الإعسار.\r\n6.	مخاطر عدم توزيع الاستثمار: هي عدم تحقيق المستثمر أي تنويع في المحفظة الاستثمارية، ويمكن تجنيبها بتوزيع مبالغ الاستثمار على شركات متعددة.\r\n7.	صعوبة التخارج: هي ظروف خاصة لقابلية التخارج ولا توجد سوق ثانوية لتداول الصكوك في هذه اللحظة.\r\n8.	نظام مكافحة جرائم المعلوماتية: الصادر بالمرسوم الملكي رقم (م/17) عام 1428هـ.\r\n9.	نظام مكافحة غسل الأموال: الصادر بالمرسوم الملكي رقم (م/20) عام 1439هـ.\r\n10.	الهيئة: تعني هيئة السوق المالية بالمملكة العربية السعودية.\r\n11.	حساب العميل: يعني حساب العميل الاستثماري أو حساباته الاستثمارية لدى الشركة بالريال السعودي والمخصصة لتنفيذ القيود النقدية المقابلة لعمليات الاستثمار\r\n12.	تعليمات العميل: تعني جميع الأوامر والتعليمات والطلبات النظامية والمشروعة المبلغة و/أو المسلمة منه للشركة بشأن أية عملية من عمليات الاستثمار والخدمات الأخرى التي تقدمها له الشركة وفق الإجراءات والعقود والاتفاقيات المنظمة لها.\r\n\r\nالمادة الثانية: التعريف بالمنصة:\r\n1.	هي منصة عبر الإنترنت تمكن المستخدمين من الوصول إلى العروض المقدمة من قبل الشركات المدرجة في المنصة من خلال إصدار أدوات الدين والاستثمار بها، والاستثمار فيها على أساس اتفاقية استثمار، ولهذا الغرض تنشر الشركات معلوماتها عبر المنصة.\r\n2.	في حالة الاستثمار من قبل المستخدمين لا تصبح التنافسية المالية طرفًا متعاقدًا بنفسها، ويبرم الاستثمار فقط بين المستخدمين والشركة المستثمر بها.\r\n3.	يجب على الشركة المصدرة التي تقدم دعوتها للمستخدمين لتقديم عروضهم بناء على حملة إصدار الصكوك توفير المعلومات الخاصة بالاستثمار الجماعي على منصة التنافسية المالية.\r\n4.	لا تتحمل التنافسية المالية مدى مصداقية البيانات التي تقدمها الشركة المصدرة.\r\n5.	تسعى التنافسية المالية لتطوير خدماتها باستمرار، مما قد يستدعي في بعض الأحيان بإلغاء الخدمة مؤقتا أو بشكل دائم.\r\n6.	يسري استخدام المنصة داخل المملكة العربية السعودية فقط.\r\n\r\nالمادة الثالثة: المشغل والمزود للمنصة:\r\nشركة التنافسية المالية هي المشغل والمزود لمنصة التنافسية المالية، والخدمة المقدمة تخضع لشروط التنافسية المالية التالية التي يجب أن تطبق في النسخة السارية وقت تسجيل المستخدم.\r\n\r\nالمادة الرابعة: التسجيل:\r\n1.	يجب التسجيل كمستخدم في بعض أقسام منصة التنافسية المالية.\r\n2.	يدخل المستخدم في عقد استخدام مع شركة التنافسية المالية بمجرد التسجيل.\r\n3.	تقوم التنافسية المالية– في بعض الأحيان – بالتحقق من المستخدم باستخدام خدمة \"يقين\" المقدمة من \"علم\".\r\n4.	يجب على المستخدم أن يكون ذا أهلية وقدرة كافية على التعاقد.\r\n5.	يجب تقديم كافة البيانات المطلوبة من الأفراد أو المنشآت للتنافسية المالية خلال عملية التسجيل، ويتحمل المستخدم المسؤولية الكاملة حال إدخاله البيانات غير الصحيحة خلال عملية التسجيل أو أي مرحلة من مراحل استخدام خدمات المحفظة.\r\n6.	يجب على العميل تقديم أي معلومات إضافية للتثبت من هويته أو لإثبات موثوقية أي أداة تمويل يسجلها المستخدم لاستخدامها مع التنافسية المالية.\r\n7.	يجوز للتنافسية المالية أو طرف ثالث تتعاقد معه القيام بكافة التحريات التي تراها ضرورية للتحقق من المعلومات التي يتم تقديمها للتنافسية المالية، على سبيل المثال لا الحصر: فحص قواعد البيانات التجارية أو التقارير الائتمانية.\r\n8.	لا تضمن التنافسية المالية ما يجري أثناء اتخاذ إجراءات التحقق من هوية المستخدم.\r\n9.	يجب على المستخدم تصحيح بياناته فورا في حال تغيرها أو إدخالها بشكل غير كامل أو غير صحيح.\r\n10.	يجب على المستخدم التأكد من سرية كلمة المرور.\r\n11.	يجب إبلاغ التنافسية المالية فورا للاستخدام غير المصرح لكلمة المرور أو حساب المستخدم.\r\n12.	لا يجوز استخدام الحساب لغير المستخدم سواء كان ذلك الشخص طبيعيًا أو معنويًا.\r\n13.	تكون اتفاقية المستخدم واجبة على الطرفين من خلال النقر على رابط التأكيد المرسل عبر البريد الإلكتروني للمستخدم.\r\n14.	تكون مدة اتفاقية المستخدم غير محددة بوقت معين.\r\n15.	يحق للتنافسية المالية أو للمستخدم إنهاء اتفاقية المستخدم بأي وقت دون إشعار مسبق منها على سبيل المثال: حذف حساب المستخدم.\r\n16.	تطبق جميع حدود المسؤولية والتعويضات في هذه الاتفاقية، حتى بعد إنهاء اتفاقية العميل .\r\n17.	تقدم الشركة خدماتها ومنتجاتها للعميل حسب تصنيفه وتنفذ أوامره وتعليماته المشروعة ذات العلاقة وفقاً لأحكام هذه الاتفاقية\r\n\r\nالمادة الخامسة: اتفاق الوكالة بالاستثمار:\r\n1.	يجب على العميل تعبئة النماذج على منصة التنافسية المالية والنقر على زر \"استثمر\" نهاية النموذج.\r\n2.	يقر العميل بقبول الاستثمار في الشركة المصدرة ووفقًا لشروطها.\r\n3.	يجب بلوغ الحد الأدنى لمبلغ الاستثمار للجولة والمتفق عليه مع الشركة المصدرة سلفًا لكي تكون اتفاقية الاستثمار نافذة.\r\n4.	يجوز إبرام عقد مكتوب بالإضافة إلى الإجراء المذكور أعلاه.\r\n5.	يلتزم العميل باتفاق الاستثمار دون أي مطالبة بإبرام اتفاقية استثمار مستقلة.\r\n6.	تلتزم الشركة بالمدة المحددة لعرض الاستثمارات على منصة التنافسية المالية.\r\n7.	تلتزم التنافسية المالية بتزويد كافة الأطراف المتعاقدة بالبيانات اللازمة للتواصل مع الطرف الآخر.\r\n8.	تلتزم التنافسية المالية بإرسال جميع المستندات إلكترونيًا من خلال البريد الإلكتروني العميل .\r\n9.	يتحمل العميل المسؤولية بكافة المستندات المرسلة من تلقاء نفسه بشكل إلكتروني أو مادي.\r\n10.	عملاً بنص لوائح هيئة السوق المالية يلزم على الشركة الاحتفاظ بأموال العميل في حساب باسمه لدى أحد البنوك المحلية ويوافق العميل على أحقية التنافسية المالية بالحصول على جميع العوائد والأرباح العائدة من الاحتفاظ بأموال العملاء في هذه الحسابات. \r\n11.	تقوم الشركة بناءً على تعليمات العميل بتنفيذ جميع العمليات المتعلقة بالاستثمار على أساس نقدي من خلال حسابه الاستثماري.\r\n12.	إذا ما حدث خطأ غير مقصود من جانب الشركة أو خلل بنظامها الآلي أدى إلى إضافة أي مبلغ لحساب العميل الاستثماري دون وجه حق أو تمكينه من الاستثمار على المكشوف، فإن العميل يقر بأن المبلغ أصبح مديونية ويلتزم بتغطية مديونية حسابه الاستثماري في موعد أقصاه يوم العمل التالي. \r\n\r\nالمادة السادسة: حدود المسؤولية:\r\n1.	تتحمل التنافسية المالية المسؤولية نتيجة الإهمال الجسيم أو  إذا فشلت في الوفاء بواجب يكون الوفاء به ضروريًا لأداء العقد على النحو الصحيح والذي يمكن أن يعتمد على الطرف المتعاقد الآخر – الواجب الأساسي –.\r\n2.	في كل الأحوال الأخرى لا يكون الطرفان مسؤولين عن أي أضرار من أي نوع بغض النظر عن موضوع المطالبة بما في ذلك المسؤولية عن العقد.\r\n3.	في حال بطلان اتفاقية الوكالة بالاستثمار تقتصر المطالبات المحتملة للمستخدم ضد التنافسية المالية الناتجة عن هذه الحقيقة على استرداد مبلغ الاستثمار فقط.\r\n4.	لا تتحمل التنافسية المالية أي مسؤولية إضافية على ما ذكر أعلاه، منها الحالات الآتية: خصائص الخدمات أو الأضرار المستحقة وفقا لحدود المسؤولية للمنتج أو الأضرار الناجمة عن فقدان الحياة أو الإصابة الجسدية أو الأضرار بالصحة.\r\n5.	تشمل المسؤولية موظفي التنافسية المالية والوكلاء المباشرين والأطراف الثالثة الأخرى التي تستخدمها التنافسية المالية للوفاء بالعقد.\r\n6.	يحق للشركة أن ترفض تنفيذ أية عمليات أو تعليمات للعميل إذا رأت وفق تقديرها المطلق أن الرصيد الدائن بحسابه الاستثماري لا يكفي لذلك أو لن يكون كافياً في تاريخ تنفيذ العملية.\r\n\r\nالمادة السابعة: المخاطر العامة:\r\nيرتبط الاستثمار بالشركات الناشئة بمخاطر عالية، وقد يؤدي إلى الخسارة الكاملة لاستثمارك. يجب ألا تستثمر الأموال التي لا يمكنك تحمل خسارتها، وفي حال الخسارة يُقتصر على المبلغ المستثمر فقط. الاستثمار من خلال التنافسية المالية هو استثمار طويل الأجل ومناسب للمستثمرين على المدى الطويل. إن فرص الاستثمار في الوقت الحالي مخصصة للأشخاص المقيمين في المملكة العربية السعودية\r\n1.	يقر العميل بعلمه واطلاعه على المخاطر المصاحبة بالاستثمار في صكوك الشركات الناشئة والمصدرة بمنصة التنافسية المالية وأن أي دخل يتحقق منها، يمكن أن ينخفض أو يرتفع وأنه من المحتمل أن تنخفض قيمتها لتصبح دون مستوى الاستثمارات الأصلية.\r\n2.	يقر العميل بعلمه واطلاعه  بأن الاستثمار طويل الأجل، وذلك من خلال تقييم الفرص وإجمالي مخاطر الخسارة ومخاطر الإعسار ومخاطر التأرجح ومخاطر عدم توزيع الاستثمار وصعوبة التخارج والمخاطر المرتبطة بأنشطة الاستثمار والالتزامات أو التنبؤات حول الأداء المستقبل.\r\n3.	تلتزم التنافسية المالية بدورها في المنصة، ولا تقدم خدمات أعمال الاستشارة.\r\n4.	تلتزم الشركات المصدرة بصحة البيانات المقدمة، وتخلي التنافسية المالية مسؤوليتها عن مدى مصداقية البيانات.\r\n5.	لا تضمن التنافسية المالية التوقعات المستقبلية للتطوير الناجح التي تقدمها الشركات المصدرة، ويتحمل العميل كافة القرارات الاستثمارية بشكل مستقل ويتحمل أي مخاطر مستقبلية.\r\n6.	للعميل وحده الخيار في الاستثمار في الشركة المطروحة أم لا.\r\n7.	يجب على العميل الاطلاع على كافة العواقب النظامية والاقتصادية والضريبية ذات الصلة بالاستثمار قبل الاستثمار وأثناء فترة الاحتفاظ.\r\n8.	يقر ويتعهد العميل بالتزامه بنظام السوق المالية ولوائحه التنفيذية، وتعليمات تصريح تجربة التقنية المالية، والأنظمة واللوائح الأخرى المعمول بها في المملكة لا سيما نظام جرائم الإرهاب وتمويله ونظام مكافحة غسل الأموال ولائحته التنفيذية وأي تحديثات تطرأ على ما سبق من وقت لأخر.\r\n\r\nالمادة الثامنة: السرية والإفصاح والخصوصية:\r\n1.	السرية: يتعين على الشركة أن تحافظ على سرية معلومات العميل بما في ذلك بياناته لديها والمعلومات التي حصلت عليها منه وتعاملاته معها وعدم إفشائها أو الإفصاح عنها للغير والاستثناء من ذلك إذا كان الإفصاح عنها مطلوباً عملاً بأحكام نظام السوق المالية ولوائحه التنفيذية أو أية أنظمة أخرى مرعية ذات علاقة أو إذا كان ذلك ضرورياً لتنفيذ عملية أو أداء خدمة للعميل أو إذا وافق العميل على ذلك صراحة.\r\n2.	يقر العميل بأنه قد اطلع على الاتفاقية والملاحق والنماذج المرفقة بها، وإشعار الخصوصية المنشور على الرابط التالي (https://www.cfc.sa/privacy-policy)، ومع الإقرار المسبق بأن كافة هذه النماذج والملاحق هي عرضة للتعديل أو الحذف أو الإضافة كليا أو جزئياً من وقت لأخر وتفهمها جيداً وقبل بها جزءاً لا يتجزأ من هذه الاتفاقية وأنه مسؤول عن صحة واكتمال وسريان مفعول ودقة بيانات حقولها وما تضمنته من معلومات والتزامه بإرفاق وتسليم المستندات والوثائق الثبوتية المؤيدة والمؤكدة لذلك.\r\n3.	يقر العميل بأنه يلزم عليه أخذ الحيطة والحذر في تعاملاته الإلكترونية والمحافظة على كلمة المرور وعدم إفشائها لأي شخص كان بمن فيهم موظفي الشركة وأنه لا يحق له الرجوع على الشركة أو مطالبتها بأية خسائر أو أضرار قد تلحق به جراء إفصاحه أو معرفة الغير لكلمة المرور وتنفيذ أي عملية بموجبه وبتحمله منفرداً كافة التبعات.\r\n\r\n', 1, 1, '2022-11-23 11:29:13', '2022-12-02 15:01:33'),
